(NULL, '2026 年国家公务员考试招考公告', '公告', '报考条件详解、报名流程、职位表筛选、考试日程、体检考察与 FAQ（6 章）。', 'assets/resources/15-gk-2026-notice.html'),
(NULL, '2026 年各省公务员考试政策汇总', '公告', '联考省份表、单独命题省份、选调生事业单位、时间节点与国考省考区别。', 'assets/resources/16-provincial-policy.html'),
(NULL, '国考报名资格审查与调剂公告', '公告', '审查材料清单、调剂条件与流程、选岗策略及常见问题解答。', 'assets/resources/17-gk-tiaoji.html'),
(7, '2026 年国考申论大纲专项解读', '资料', '三类职位试卷对比、作答规范细则、常见失分点清单 + 2 道代表性样题。', 'assets/resources/18-gk-2026-shenlun-outline.html'),
(1, '2023 年国考行测真题回顾', '真题', '2023—2025 三年对比分析、命题趋势研判、12 道代表性真题精讲。', 'assets/resources/19-gk-2023-xingce.html'),
(1, '行测考前冲刺模拟卷（二）', '模拟题', '130 题全真结构、20 道精选模拟题含解析、分模块限时策略。', 'assets/resources/20-mock-xingce-2.html'),
(4, '逻辑判断 50 题专项训练', '模拟题', '翻译推理、加强削弱、前提假设等六大题型 + 25 道精选样题。', 'assets/resources/21-luoji-panduan-50.html'),
(7, '2026 申论热点素材库', '资料', '15 个国考高频热点，含核心金句、典型案例、对策表述三要素。', 'assets/resources/22-shenlun-sucai-2026.html'),
(NULL, '国考职位表使用指南', '资料', '职位表字段解读、五步筛选法、专业目录对照 + 6 个报岗案例分析。', 'assets/resources/23-gk-position-guide.html');
INSERT INTO questions (subject_id, resource_id, type, content, options, correct_answer, explanation, tips) VALUES
(1, 3, '单选', '党的二十大报告指出，中国式现代化是人口规模巨大的现代化，是全体人民共同富裕的现代化，是物质文明和精神文明相协调的现代化，是人与自然和谐共生的现代化，是走和平发展道路的现代化。关于中国式现代化，下列说法正确的是：', '["A. 中国式现代化否定了其他国家走向现代化的路径", "B. 中国式现代化打破了「现代化=西方化」的迷思", "C. 中国式现代化以资本为中心，追求物质极大丰富", "D. 中国式现代化主要依靠外部援助实现赶超"]', 'B', '解析：中国式现代化创造了人类文明新形态，打破了「现代化=西方化」的迷思，拓展了发展中国家走向现代化的路径选择，而非否定他国路径。A 项「否定他国路径」表述绝对化，与「拓展路径选择」不符；C 项与「以人民为中心」的发展思想相悖；D 项与「独立自主、自力更生」的基本国策不符。本题考查二十大报告关于中国式现代化五大特征的准确理解，属于表述辨析类高频考点。', '政治理论 · 第 3 题'),
(1, 3, '单选', '新发展理念是一个系统的理论体系，回答了关于发展的目的、动力、方式、路径等一系列理论和实践问题。下列关于新发展理念的表述，正确的是：', '["A. 创新是引领发展的第一动力，注重解决发展动力问题", "B. 协调是发展的第一动力，注重解决发展不平衡问题", "C. 绿色是发展的根本目的，注重解决人与自然和谐问题", "D. 共享是发展的本质特征，注重解决发展内外联动问题"]', 'A', '解析：新发展理念「创新、协调、绿色、开放、共享」各有定位：创新解决动力问题，协调解决不平衡问题，绿色解决人与自然和谐问题，开放解决内外联动问题，共享解决公平正义问题。B 项将「协调」误作第一动力；C 项发展的根本目的是满足人民美好生活需要，非绿色本身；D 项「共享」解决公平正义，「开放」才对应内外联动。备考时需熟记五大理念与所解决问题的对应关系。', '政治理论 · 第 7 题'),
(1, 3, '单选', '习近平总书记强调，全面建设社会主义现代化国家、全面推进中华民族伟大复兴，关键在党。关于全面从严治党，下列说法不正确的是：', '["A. 要以党的政治建设为统领，把党的政治建设摆在首位", "B. 思想建设是党的基础性建设，要把坚定理想信念作为首要任务", "C. 可以只对「关键少数」严格要求，对普通党员适当放宽标准", "D. 作风建设必须常抓不懈，力戒形式主义、官僚主义"]', 'C', '解析：全面从严治党覆盖全体党员、全过程、全方位，管党治党没有「特殊党员」，不存在对普通党员「适当放宽」的空间。A、B、D 均为党内法规与二十大报告中的标准表述。本题易错点在于考生可能误以为「抓关键少数」意味着可以放松对多数党员的要求，实际上「关键少数」强调的是领导干部示范带头，而非降低对普通党员的标准。', '政治理论 · 第 12 题'),
(1, 3, '单选', '总体国家安全观强调，国家安全是安邦定国的重要基石。下列举措中，最直接体现「统筹发展和安全」的是：', '["A. 在扩大对外开放的同时，完善重要领域安全审查机制", "B. 大幅增加国防预算，削减民生领域财政支出", "C. 暂停一切对外经贸合作，集中精力搞内循环", "D. 将安全工作完全交给专门部门，经济社会发展部门不予参与"]', 'A', '解析：「统筹发展和安全」要求在发展中固安全、在安全中谋发展，而非对立或偏废。A 项在扩大开放（发展）的同时完善安全审查（安全），体现统筹兼顾。B 项削减民生支出并非统筹之道；C 项「暂停一切对外合作」过于极端；D 项将安全与发展割裂，违背「统筹」要求。总体国家安全观是 2025 年政治理论新增高频考点，需与「新安全格局」一并掌握。', '政治理论 · 第 18 题'),
(6, 3, '判断', '根据《中华人民共和国行政复议法》（2024 年修订），下列说法正确的是：', '["A. 公民对县级人民政府工作部门的行政行为不服，只能向该部门的本级人民政府申请行政复议", "B. 行政复议机关受理行政复议申请后，应当全面审查被申请行政行为的合法性与适当性", "C. 行政复议决定书一经作出即发生法律效力", "D. 申请人不得在行政复议期间向人民法院提起行政诉讼"]', 'B', '解析：2024 年修订的行政复议法强化了复议机关的全面审查职责，包括合法性与适当性。A 项错误：对县级政府部门行为不服，可向本级政府申请复议，也可向上一级主管部门申请复议（「二选一」）。C 项错误：复议决定书需依法送达后才发生法律效力。D 项错误：复议与诉讼的衔接有明确规定，部分情形下复议前置，部分可自由选择，并非一律禁止起诉。新法修订要点是 2025 常识法律类头号热点。', '常识判断 · 第 22 题'),
(6, 3, '判断', '2024 年我国航天事业取得一系列重大突破。下列与之对应正确的是：', '["A. 「嫦娥六号」——首次实现月球背面采样返回", "B. 「天问三号」——首次实现火星表面载人登陆", "C. 「神舟十七号」——首次完成中国空间站基本构型组装", "D. 「北斗三号」——全球卫星导航系统于 2024 年首次建成"]', 'A', '解析：嫦娥六号于 2024 年成功完成人类首次月球背面采样返回，是我国深空探测里程碑。B 项天问系列目前为无人探测，尚未实现载人登陆；C 项空间站基本构型已于 2022 年前后完成，神舟十七号为常态化驻留任务；D 项北斗三号全球系统于 2020 年已建成开通，非 2024 年。科技常识题近年侧重「首次」「突破」类成就，复习时按时间线整理效率更高。', '常识判断 · 第 27 题'),
(6, 3, '判断', '下列情形中，符合《中华人民共和国行政处罚法》规定的是：', '["A. 对当事人的同一个违法行为，可以给予两次以上罚款的行政处罚", "B. 行政机关作出降低资质等级的处罚前，应当告知当事人有要求听证的权利", "C. 行政处罚可以由受委托的组织以自己的名义实施", "D. 违法行为在二年内未被发现的，一律不再给予行政处罚"]', 'B', '解析：降低资质等级属于较重行政处罚，依法应告知听证权利。A 项违反「一事不再罚」原则；C 项受委托组织应以委托机关名义处罚，不能以自己名义实施；D 项「一律不再处罚」表述绝对，法律对连续或继续状态的违法行为另有规定。行政执法类考生应重点掌握行政处罚种类、听证程序、首违不罚等新规。', '常识判断 · 第 33 题'),
(2, 3, '单选', '基层治理能否有效，关键看是否能把党的路线方针政策落实到「最后一公里」。数字技术不是万能钥匙，若脱离群众需求搞「数字形式主义」，反而会增加基层负担。填入画横线部分最恰当的一项是：', '["A. 缘木求鱼", "B. 削足适履", "C. 锦上添花", "D. 雪中送炭"]', 'B', '解析：文段强调不能不顾实际需求强行套用技术。「削足适履」比喻不顾具体情况生搬硬套，与「脱离群众需求」形成精准呼应。A 项「缘木求鱼」比喻方向或方法错误，侧重「不可能达到目的」，不如 B 贴切；C、D 均为褒义成语，与批评「数字形式主义」的负面语境不符。逻辑填空解题顺序：定关系（转折/并列）→ 辨感情色彩 → 验搭配。', '言语理解 · 逻辑填空 · 第 38 题'),
(2, 3, '单选', '文化遗产保护不是把古迹______在玻璃罩里，而是在传承中赋予其新的时代内涵，让历史文脉与当代生活______。依次填入画横线部分最恰当的一项是：', '["A. 封存 交相辉映", "B. 冻结 相得益彰", "C. 封闭 一脉相承", "D. 搁置 并行不悖"]', 'B', '解析：第一空与「不是……而是……」的否定结构呼应，需表达「静止僵化」之意，「冻结」比「封存」更能体现缺乏活力的负面意味。第二空强调历史与当代相互促进、共同增色，「相得益彰」指双方互相配合使优点更加突出，最为恰当。「交相辉映」侧重光彩相互映照，多用于景物；「一脉相承」强调传承关系，非互动关系；「并行不悖」指同时进行不冲突，程度偏弱。', '言语理解 · 逻辑填空 · 第 44 题'),
(2, 3, '单选', '「新质生产力」不等于忽视传统产业。传统产业是现代化产业体系的基底，通过技术改造和数字化转型，同样能够焕发新的竞争力。一些地方的实践表明，推动设备更新、工艺升级、绿色改造，可以让「老树发新芽」。这段文字意在说明：', '["A. 发展新质生产力必须完全淘汰传统产业", "B. 传统产业与新质生产力相互对立、不可兼得", "C. 传统产业可通过升级改造融入现代产业体系", "D. 技术进步只对新兴产业发挥作用"]', 'C', '解析：文段结构为「观点—解释—例证」。核心句是「传统产业是基底」「通过改造焕发竞争力」，意在说明传统产业并非被否定对象，而是可以升级融入体系。A、B 项与文意直接矛盾；D 项「只对新兴产业」过于绝对，与「老树发新芽」例证相悖。片段阅读主旨题优先找转折后、对策句及总结句，切忌过度推断。', '言语理解 · 片段阅读 · 第 51 题'),
(2, 3, '单选', '行政执法既要维护法律权威，也要体现人文关怀。「首违不罚」「轻微免罚」并非对违法行为的纵容，而是在坚持法治底线的前提下，给予初次违法、危害轻微者自我纠正的机会，从而降低执法成本、减少社会对立。下列说法与这段文字相符的是：', '["A. 「首违不罚」意味着所有初次违法均可免除处罚", "B. 柔性执法与严格执法是相互矛盾、不可统一的", "C. 「首违不罚」体现的是在法治框架内兼顾温度与力度", "D. 行政执法应当一律从重处罚以树立法律权威"]', 'C', '解析：细节判断题需逐项回原文比对。文段明确「并非纵容」「坚持法治底线」「给予自我纠正机会」，C 项准确概括。A 项「所有初次违法均可免除」扩大范围，原文限定「危害轻微」；B 项文段强调二者可统一；D 项「一律从重」与文段柔性执法导向相反。2025 年言语材料政务化明显，执法、治理类文本占比上升。', '言语理解 · 片段阅读 · 第 58 题'),
(3, 3, '单选', '甲、乙两人同时从 A 地出发前往 B 地，甲速度 60 千米/小时，乙速度 40 千米/小时。甲到达 B 地后立即返回，在距 B 地 30 千米处与乙相遇。问 A、B 两地相距多少千米？', '["A. 120", "B. 135", "C. 150", "D. 180"]', 'C', '解析：设 A、B 相距 S 千米。相遇时甲行 S+30 千米，乙行 S−30 千米，两人用时相同。列比例方程：(S+30)/60 = (S−30)/40。交叉相乘：40(S+30) = 60(S−30)，40S+1200 = 60S−1800，20S = 3000，S = 150。验证：甲行 180 km 用 3 h，乙行 120 km 用 3 h，吻合。行程问题核心：同段时间内路程比等于速度比，即 (S+30):(S−30) = 60:40 = 3:2。', '数量关系 · 第 68 题'),
(3, 3, '单选', '某项目由甲、乙两队合作 12 天可完成。已知甲队单独完成需 20 天，问乙队单独完成需要多少天？', '["A. 24 天", "B. 28 天", "C. 30 天", "D. 36 天"]', 'C', '解析：赋值工程总量为 20 与 12 的最小公倍数 60。甲效率 = 60÷20 = 3，甲乙合作效率 = 60÷12 = 5，乙效率 = 5−3 = 2。乙单独完成需 60÷2 = 30 天。工程问题「赋值法」是国考数量第一技巧：当只给时间、不求具体工作量时，赋值总量为各完成时间的最小公倍数，可迅速求效率。', '数量关系 · 第 71 题'),
(3, 3, '单选', '某单位组织职工植树，若每人植 4 棵，则剩余 3 棵树苗；若每人植 5 棵，则缺 7 棵树苗。问该单位有多少名职工？', '["A. 8 人", "B. 9 人", "C. 10 人", "D. 11 人"]', 'C', '解析：设职工 x 人，树苗 y 棵。根据题意：4x + 3 = y，5x − 7 = y。联立方程：4x + 3 = 5x − 7，解得 x = 10。代入验证：树苗 = 4×10+3 = 43 棵，10 人每人 5 棵需 50 棵，缺 7 棵，43+7=50，正确。盈亏问题也可口算：每人多植 1 棵共需多 3+7=10 棵，故职工 10 人。', '数量关系 · 第 74 题'),
(4, 3, '判断', '「首因效应」是指人们在对他人形成印象的过程中，最初获得的信息比后来获得的信息影响更大，从而决定整体印象的现象。下列属于首因效应的是：', '["A. 小李面试时着装得体、表达流畅，考官对其留下良好第一印象，后续表现平平也未改变评价", "B. 小张得知同事迟到后，认为其一向不守时，忽略了其平日早到的事实", "C. 小王因最近一次项目失误，被领导认定能力不行", "D. 小赵听说某餐厅卫生差后，即使实地体验不错也不愿再去"]', 'A', '解析：首因效应关键词：「最初获得的信息」「影响更大」「决定整体印象」。A 项面试初印象主导最终评价，完全符合。B 项根据最近迟到事件形成印象，属近因效应；C 项由最近一次失误决定评价，亦为近因效应；D 项根据「听说」的先前信息拒绝改变，更接近晕轮效应或刻板印象，且非面对面形成印象的典型场景。定义判断技巧：提取定义关键词 → 逐项比对 → 选最贴合项，切忌主观联想。', '判断推理 · 定义判断 · 第 85 题'),
(4, 3, '判断', '钢笔：书写 相当于 （ ）', '["A. 轮船：运输", "B. 书籍：纸张", "C. 窗户：玻璃", "D. 树木：森林"]', 'A', '解析：钢笔的主要功能是书写，二者为「工具：核心功能」关系。轮船的主要功能是运输，逻辑一致。B 项书籍由纸张制成，为原材料/成品关系；C 项窗户包含玻璃，为组成关系；D 项树木组成森林，为部分与整体关系。类比推理标准流程：先定一级关系，若无法区分再比对二级属性（如是否人造、是否职业相关等）。', '判断推理 · 类比推理 · 第 92 题'),
(4, 3, '判断', '某单位规定：如果年度考核优秀，则可以优先参加培训。已知小李没有优先参加培训，则可以推出：', '["A. 小李年度考核一定不优秀", "B. 小李年度考核可能优秀", "C. 小李年度考核一定优秀", "D. 无法判断小李考核是否优秀"]', 'A', '解析：翻译推理：优秀 → 培训（参加培训）。 contrapositive（逆否命题）：¬培训 → ¬优秀。小李未获培训，根据逆否命题可确定其考核一定不优秀，选 A。常见陷阱：否前（考核不优秀）不能推出否后（不培训），但否后（未培训）一定可以推出否前（不优秀）。「可能优秀」看似留有余地，实则违反形式逻辑确定性。', '判断推理 · 逻辑判断 · 第 105 题'),
(5, 3, '单选', '2024 年前三季度，某省规模以上工业增加值同比增长 7.8%。分门类看，装备制造业增加值增长 11.2%，占规模以上工业比重为 32.5%；高技术制造业增长 9.6%。问 2024 年前三季度，该省装备制造业增加值同比增速比规模以上工业：', '["A. 高不到 3 个百分点", "B. 高 3 个百分点以上", "C. 低不到 3 个百分点", "D. 低 3 个百分点以上"]', 'B', '解析：本题考查增长率作差。装备制造业增速 11.2%，规模以上工业增速 7.8%，差值 = 11.2% − 7.8% = 3.4 个百分点，高于 3 个百分点，选 B。注意：「个百分点」用于百分数相减，不可表述为「百分之几」增速差。此类题目在 2025 年资料分析中出现频率极高，计算量小，属于必拿分题。', '资料分析 · 第 118 题'),
(5, 3, '单选', '2023 年某市进出口总额 8560 亿元，同比增长 6.2%。其中出口 5120 亿元，增长 8.1%；进口 3440 亿元，增长 3.5%。问 2023 年该市贸易顺差比 2022 年：', '["A. 增加了不到 500 亿元", "B. 增加了 500 亿元以上", "C. 减少了不到 500 亿元", "D. 减少了 500 亿元以上"]', 'A', '解析：2023 年顺差 = 5120 − 3440 = 1680 亿元。求 2022 年顺差需分别求基期：2022 出口 ≈ 5120÷1.081 ≈ 4740 亿元；2022 进口 ≈ 3440÷1.035 ≈ 3320 亿元；2022 顺差 ≈ 4740 − 3320 = 1420 亿元。增加量 ≈ 1680 − 1420 = 260 亿元，不到 500 亿元，选 A。易错点：不可直接用增长率相减求顺差变化，必须分别求基期再相减。', '资料分析 · 第 123 题'),
(5, 3, '单选', '某市 2023 年粮食产量 280 万吨，同比增长 2.5%；种植面积 520 万亩，同比下降 1.0%。问 2023 年该市粮食亩产量（单产）同比增长约：', '["A. 2.0%", "B. 3.5%", "C. 4.0%", "D. 5.5%"]', 'B', '解析：亩产量 = 产量 ÷ 种植面积。当求「平均数的增长率」时，可用近似公式：产量增长率 − 面积增长率 = 2.5% − (−1.0%) = 3.5%。精确验证：2022 产量 ≈ 280÷1.025 ≈ 273.2 万吨，2022 面积 ≈ 520÷0.99 ≈ 525.3 万亩；2022 单产 ≈ 0.520，2023 单产 = 280÷520 ≈ 0.538，增长率 ≈ (0.538−0.520)÷0.520 ≈ 3.5%。平均数增长率公式是资料分析进阶必背公式。', '资料分析 · 第 128 题'),
(2, 4, '单选', '「新质生产力」不等于忽视传统产业。传统产业是现代化产业体系的基底，通过技术改造和数字化转型，同样能够焕发新的竞争力。这段文字意在说明：', '["A. 发展新质生产力必须完全淘汰传统产业", "B. 传统产业与新质生产力相互对立、不可兼得", "C. 传统产业可通过升级融入现代产业体系", "D. 技术进步只对新兴产业发挥作用"]', 'C', '解析：文段核心句为「传统产业是基底」「通过改造焕发竞争力」，强调传统产业可升级而非被否定。A、B、D 均与文意相悖。2025 对比：同类题材在 2025 年言语中仍高频出现，且材料篇幅更长、论证更完整，但主旨提炼方法不变。', '言语理解 · 2024 样题 1 · 片段阅读'),
(2, 4, '单选', '乡村振兴不能搞「一刀切」，各地资源禀赋不同，发展路径也应______。盲目照搬外地模式，往往______，难以形成可持续的内生动力。', '["A. 因地制宜 水土不服", "B. 千篇一律 事半功倍", "C. 标新立异 屡试不爽", "D. 墨守成规 适得其反"]', 'A', '解析：第一空与「资源禀赋不同」呼应，应填「因地制宜」。第二空描述盲目照搬的负面结果，「水土不服」比喻不适应本地条件，与语境契合。B 项「事半功倍」为褒义；C 项「屡试不爽」意为屡次试验都不错，与文意相反；D 项「墨守成规」形容固守旧规，与「照搬外地」不完全对应。', '言语理解 · 2024 样题 2 · 逻辑填空'),
(2, 4, '判断', '「微腐败」看似金额不大，却直接损害群众切身利益，侵蚀党的执政根基。治理微腐败不能仅靠「大扫除」式整治，更要堵塞制度漏洞，让权力运行在阳光下。下列说法与原文相符的是：', '["A. 微腐败危害有限，不必纳入反腐败工作重点", "B. 治理微腐败的关键在于一次性集中整治", "C. 制度约束是治理微腐败的重要路径", "D. 群众监督无法对微腐败产生制约作用"]', 'C', '解析：文段对策句为「堵塞制度漏洞」，C 项准确概括。A 与「侵蚀执政根基」矛盾；B 与「不能仅靠大扫除」矛盾；D 无中生有。2025 对比：2025 年言语中执法、廉政类材料显著增多，此类题型备考价值持续上升。', '言语理解 · 2024 样题 3 · 细节判断'),
(4, 4, '判断', '「行政指导」是指行政机关在其职责范围内，为实现一定行政目的，对公民、法人或其他组织采取鼓励、引导、建议等非强制性方式，促使其作出或不作出一定行为的活动。下列属于行政指导的是：', '["A. 市场监管局对违规企业作出罚款 5 万元的处罚决定", "B. 发改委发布产业政策，鼓励企业加大研发投入", "C. 交警对违章停车车辆实施强制拖移", "D. 税务局追缴某企业欠缴税款并加收滞纳金"]', 'B', '解析：行政指导关键词：「非强制性」「鼓励、引导、建议」。B 项「鼓励企业加大研发」符合。A、C、D 均为具有法律效力的强制性行政行为。2025 对比：2025 年定义判断题干更长，但提取「强制性 vs 非强制性」这一关键词的方法不变。', '判断推理 · 2024 样题 5 · 定义判断'),
(4, 4, '判断', '研究表明：经常锻炼的人患心血管疾病的概率较低。据此，有人认为，只要坚持锻炼，就不会患心血管疾病。下列哪项如果为真，最能削弱上述观点？', '["A. 锻炼有助于增强体质，改善睡眠质量", "B. 心血管疾病与遗传、饮食、压力等多种因素相关，锻炼不能完全消除患病风险", "C. 很多人因工作繁忙无法坚持规律锻炼", "D. 适度锻炼比过度锻炼更有利于健康"]', 'B', '解析：原观点将「概率较低」绝对化为「不会患」，属于过度推断。B 项指出患病受多因素影响、锻炼不能完全消除风险，直接削弱「只要锻炼就不会患病」的结论。A、D 与心血管患病风险无直接削弱关系；C 讨论的是锻炼可行性，非患病概率。', '判断推理 · 2024 样题 6 · 逻辑判断'),
(3, 4, '单选', '一项工程，甲单独做 15 天完成，乙单独做 10 天完成。两人合作 3 天后，乙因事离开，甲又单独做了多少天完成全部工程？', '["A. 5 天", "B. 6 天", "C. 7 天", "D. 8 天"]', 'C', '解析：赋值总量 30（15 与 10 的最小公倍数），甲效率 2，乙效率 3。合作 3 天完成 (2+3)×3=15，剩余 15，甲单独需 15÷2=7.5 天，选项中最接近 C（7 天）。分段工程问题：先算已完成量，再求剩余工作量÷甲效率。', '数量关系 · 2024 样题 8 · 工程问题'),
(3, 4, '单选', '某会议需安排 5 人发言，其中 A 必须在 B 之前发言（不要求相邻），共有多少种安排方法？', '["A. 24 种", "B. 36 种", "C. 48 种", "D. 60 种"]', 'D', '解析：5 人全排列 5!=120 种。A 在 B 之前与 A 在 B 之后对称，各 60 种。故 A 在 B 之前有 120÷2=60 种。2025 对比：2025 年排列组合题量略增，但「对称法」「插板法」仍是核心技巧。', '数量关系 · 2024 样题 9 · 排列组合'),
(5, 4, '单选', '2023 年全社会固定资产投资 520000 亿元，增长 3.0%。其中基础设施投资增长 5.9%，制造业投资增长 6.5%，房地产开发投资下降 9.6%。问下列投资类别中，2023 年同比增速最快的是：', '["A. 全社会固定资产投资", "B. 基础设施投资", "C. 制造业投资", "D. 房地产开发投资"]', 'C', '解析：直接比较各增长率：制造业 6.5% > 基础设施 5.9% > 全社会 3.0% > 房地产 −9.6%，最快为制造业投资。此类题目无需计算，直接读数比较，是资料分析「送分题」。', '资料分析 · 2024 样题 11 · 增长率比较'),
(5, 4, '单选', '2023 年某省 GDP 为 98000 亿元，第三产业增加值 52000 亿元。问第三产业占 GDP 比重约为：', '["A. 48.5%", "B. 53.1%", "C. 56.8%", "D. 61.2%"]', 'B', '解析：比重 = 52000÷98000 ≈ 52/98 ≈ 53.1%，选 B。截位直除：52÷98，首位商 5，第二位约 3，得 53% 左右。', '资料分析 · 2024 样题 12 · 比重计算'),
(6, 4, '判断', '2024 年中央一号文件继续聚焦「三农」工作。下列举措与「确保国家粮食安全」关联最弱的是：', '["A. 实施新一轮千亿斤粮食产能提升行动", "B. 严格耕地占补平衡，守住耕地保护红线", "C. 发展乡村文化旅游，建设宜居宜业和美乡村", "D. 加强高标准农田建设，提升农业防灾减灾能力"]', 'C', '解析：A、B、D 均直接服务于粮食产能与耕地保护。C 项侧重乡村建设与文旅融合，与粮食安全关联相对较弱。审题关键是「关联最弱」，勿选表述正确但关联度低的选项。', '常识判断 · 2024 样题 13 · 时政三农'),
(6, 4, '判断', '下列中国古代典籍与其内容对应正确的是：', '["A. 《齐民要术》——农业科学技术总结", "B. 《天工开物》——医学理论与方剂", "C. 《伤寒杂病论》——工艺技术百科全书", "D. 《水经注》——天文历法推算"]', 'A', '解析：《齐民要术》为北魏贾思勰所著农业科学著作。B 项《天工开物》是工艺技术百科全书；C 项《伤寒杂病论》是医学典籍；D 项《水经注》是地理学著作。2025 对比：2025 年纯文史识记题减少，但偶仍出现，建议掌握「典籍—作者—领域」对照表。', '常识判断 · 2024 样题 14 · 历史文化'),
(6, 4, '判断', '下列关于日常生活中光的现象，说法正确的是：', '["A. 彩虹是光的色散现象，通常出现在雨后阳光照射时", "B. 镜中倒影是光的直线传播形成的", "C. 海市蜃楼是光的反射现象", "D. 小孔成像是光的折射现象"]', 'A', '解析：彩虹是阳光经水滴折射、反射、再折射后发生色散形成的。B 项镜中倒影是光的反射；C 项海市蜃楼是光的折射（不均匀介质）；D 项小孔成像是光的直线传播。科技常识题近年侧重生活应用，复习时联系日常现象记忆效果更佳。', '常识判断 · 2024 样题 15 · 科技生活'),
(1, 5, '单选', '「新质生产力」是创新起主导作用，摆脱传统经济增长方式、生产力发展路径，具有高科技、高效能、高质量特征，符合新发展理念的先进生产力质态。关于发展新质生产力，下列举措最契合的是：', '["A. 大规模上马高耗能传统产能项目", "B. 推动科技创新与产业创新深度融合", "C. 限制数字经济与人工智能发展", "D. 以要素投入扩张为主要增长动力"]', 'B', '解析：新质生产力以创新为主导，强调科技与产业融合。A、D 为传统粗放增长路径；C 与数字化、智能化发展方向相悖。2025 年政治理论中「新质生产力」是绝对高频考点，需掌握其内涵、特征与培育路径。', '模拟卷一 · 第 1 题 · 政治理论'),
(1, 5, '单选', '党的二十大报告提出「五个必由之路」，其中指出，中国特色社会主义是实现中华民族伟大复兴的必由之路。关于「五个必由之路」，下列对应关系正确的是：', '["A. 全面从严治党——坚持和发展中国特色社会主义的必由之路", "B. 团结奋斗——中国人民创造历史伟业的必由之路", "C. 贯彻新发展理念——新时代我国发展壮大的必由之路", "D. 全面深化改革开放——坚持党的全面领导的必由之路"]', 'C', '解析：五个必由之路准确对应：全面从严治党是党永葆生机活力的必由之路；团结奋斗是中国人民创造历史伟业的必由之路；贯彻新发展理念是新时代我国发展壮大的必由之路；全面深化改革开放是坚持和发展中国特色社会主义的必由之路；中国特色社会主义是实现中华民族伟大复兴的必由之路。A、D 张冠李戴，B 表述不完整。', '模拟卷一 · 第 5 题 · 政治理论'),
(1, 5, '单选', '全面从严治党是党永葆生机活力、走好新的赶考之路的必由之路。下列关于全面从严治党的表述，不正确的是：', '["A. 要以党的政治建设为统领", "B. 要把制度建设贯穿其中", "C. 可以只对部分党员严格要求、对少数干部宽松管理", "D. 必须持之以恒正风肃纪反腐"]', 'C', '解析：全面从严治党覆盖全体党员、全过程、全方位，不存在「对部分宽松」的空间。C 项表述明显错误，是本题答案。其余三项均为标准表述。', '模拟卷一 · 第 8 题 · 政治理论'),
(1, 5, '单选', '构建新发展格局是以国内大循环为主体、国内国际双循环相互促进的发展格局。下列举措中，最直接有利于增强国内大循环内生动力和可靠性的是：', '["A. 扩大高水平对外开放，吸引外资进入", "B. 加快构建全国统一大市场，破除地方保护", "C. 增加出口补贴，扩大外贸顺差", "D. 全面禁止进口消费品，保护国内产业"]', 'B', '解析：国内大循环的关键在于畅通国内经济循环、提升内生动力。构建全国统一大市场、破除地方保护和行政壁垒，有助于要素自由流动、激发内需潜力。A 侧重国际循环；C 侧重外需；D 过于极端，违背开放发展理念。', '模拟卷一 · 第 12 题 · 政治理论'),
(1, 5, '单选', '习近平总书记强调，「江山就是人民，人民就是江山」。下列选项最能体现「以人民为中心」发展思想的是：', '["A. 把 GDP 增速作为衡量发展的唯一标准", "B. 在发展中保障和改善民生，扎实推进共同富裕", "C. 优先发展资本密集型产业，扩大投资规模", "D. 以城市建设为中心，加快房地产开发"]', 'B', '解析：「以人民为中心」强调发展为了人民、发展依靠人民、发展成果由人民共享。B 项保障和改善民生、推进共同富裕，是核心体现。A 项「唯一标准」绝对化；C、D 偏离人民中心导向。', '模拟卷一 · 第 15 题 · 政治理论'),
(6, 5, '判断', '根据《中华人民共和国行政处罚法》，下列说法正确的是：', '["A. 行政处罚只能由法律设定", "B. 对当事人的同一个违法行为，不得给予两次以上罚款的行政处罚", "C. 所有行政处罚案件都必须举行听证", "D. 行政处罚决定作出后，当事人不得申请行政复议"]', 'B', '解析：「一事不再罚」是行政处罚法基本原则。A 项行政法规、地方性法规也可设定部分行政处罚；C 项只有法定较重处罚才需听证；D 项当事人可依法申请复议或提起诉讼。', '模拟卷一 · 第 23 题 · 常识判断'),
(6, 5, '判断', '下列关于我国地理国情的说法，正确的是：', '["A. 塔里木盆地是我国面积最大的盆地", "B. 长江是我国最长的内流河", "C. 秦岭—淮河一线以南为温带季风气候", "D. 青海湖是我国最大的淡水湖"]', 'A', '解析：塔里木盆地是我国面积最大的盆地。B 项长江是外流河，最长内流河为塔里木河；C 项秦岭以南为亚热带/热带季风气候；D 项青海湖是咸水湖，最大淡水湖为鄱阳湖。', '模拟卷一 · 第 28 题 · 常识判断'),
(6, 5, '判断', '2024 年我国科技创新取得重要进展。下列成就与年份对应正确的是：', '["A. 嫦娥六号完成月球背面采样返回——2024 年", "B. 北斗三号全球系统建成开通——2024 年", "C. 中国空间站基本构型建成——2024 年", "D. 第一颗人造卫星发射成功——2024 年"]', 'A', '解析：嫦娥六号于 2024 年完成人类首次月背采样返回。北斗三号 2020 年建成；空间站基本构型 2022 年前后完成；第一颗人造卫星（东方红一号）1970 年发射。', '模拟卷一 · 第 32 题 · 常识判断'),
(1, 5, '单选', '社区食堂既要解决老年人「吃饭难」，也要避免沦为______的政绩工程。运营方应建立需求调研、价格公示、满意度反馈等长效机制，让惠民设施真正______。', '["A. 昙花一现 落地生根", "B. 纸上谈兵 名噪一时", "C. 一劳永逸 喧宾夺主", "D. 好高骛远 锦上添花"]', 'A', '解析：第一空与「政绩工程」呼应，指不能持久；「昙花一现」恰当。第二空指真正发挥作用、稳定存在，「落地生根」符合。B 项「名噪一时」为短暂出名，与惠民设施长期运营语境不符。', '模拟卷一 · 第 36 题 · 逻辑填空'),
(1, 5, '单选', '行政执法规范化建设，既要防止「一刀切」的僵化执法，也要避免「老好人」式的______。只有在坚持法治底线的前提下体现人文关怀，才能让执法既有力度又有______。', '["A. 姑息迁就 温度", "B. 雷厉风行 效率", "C. 刚愎自用 权威", "D. 墨守成规 创新"]', 'A', '解析：与「老好人」对应的是对违法行为宽容迁就，「姑息迁就」恰当。第二空与「力度」并列，「温度」形成对仗，体现柔性执法。B 项「雷厉风行」为褒义，与「老好人」负面语境不符。', '模拟卷一 · 第 40 题 · 逻辑填空'),
(1, 5, '单选', '数字化转型不是简单地把线下流程搬到线上，而是要______业务流程、______数据价值，实现治理效能的整体提升。', '["A. 重塑 释放", "B. 保留 隐藏", "C. 压缩 浪费", "D. 照搬 忽视"]', 'A', '解析：数字化转型强调优化再造，「重塑流程」「释放数据价值」为常见搭配，与「整体提升」呼应。B、C、D 均为负面或消极表述，与文段积极导向矛盾。', '模拟卷一 · 第 45 题 · 逻辑填空'),
(1, 5, '单选', '「微腐败」看似金额不大，却直接损害群众切身利益，侵蚀党的执政根基。治理微腐败不能仅靠「大扫除」式整治，更要堵塞制度漏洞，让权力运行在阳光下。这段文字意在强调：', '["A. 微腐败危害巨大，必须一律适用刑事处罚", "B. 治理微腐败需标本兼治、强化制度约束", "C. 群众监督是反腐败的唯一有效途径", "D. 应大幅提高公务员薪酬以减少腐败动机"]', 'B', '解析：文段对策句为「堵塞制度漏洞，让权力运行在阳光下」，强调制度治本。A 表述极端；C「唯一」绝对化；D 无中生有。', '模拟卷一 · 第 52 题 · 片段阅读'),
(1, 5, '单选', '好的营商环境不是政府「管」出来的，而是「服务」出来的。减少不必要的审批环节、清理隐性壁垒、平等保护各类市场主体，才能激发内生动力。这段文字意在说明：', '["A. 政府应加强对市场主体的全面管控", "B. 优化营商环境关键在于转变政府职能、提升服务", "C. 审批环节越多越能保证市场安全", "D. 国有企业在营商环境建设中处于次要地位"]', 'B', '解析：核心句「不是管出来的，而是服务出来的」及后文对策，强调政府职能向服务型转变。A 与文意相反；C 与「减少审批」矛盾；D 无中生有。', '模拟卷一 · 第 58 题 · 片段阅读'),
(3, 5, '单选', '某项目由甲、乙两队合作 12 天可完成。若甲队单独做 20 天完成，问乙队单独做需要多少天？', '["A. 24 天", "B. 28 天", "C. 30 天", "D. 36 天"]', 'C', '解析：赋值总量 60，甲效率 3，合作效率 5，乙效率 2，乙单独需 30 天。工程问题为模拟卷数量部分必考题型。', '模拟卷一 · 第 66 题 · 数量关系'),
(3, 5, '单选', '甲、乙两人同时从相距 360 千米的两地相向而行，甲速 70 km/h，乙速 50 km/h，问多少小时后两人相遇？', '["A. 2 小时", "B. 3 小时", "C. 4 小时", "D. 5 小时"]', 'B', '解析：相遇时间 = 路程和 ÷ 速度和 = 360 ÷ (70+50) = 360 ÷ 120 = 3 小时。', '模拟卷一 · 第 69 题 · 数量关系'),
(3, 5, '单选', '某商品原价 200 元，先涨价 20%，再降价 20%，现价约为原价的百分之几？', '["A. 96%", "B. 100%", "C. 104%", "D. 120%"]', 'A', '解析：200×1.2×0.8=192 元，192÷200=96%。易错点：涨价降价百分比基数不同，不能抵消为 100%。', '模拟卷一 · 第 72 题 · 数量关系'),
(3, 5, '单选', '从 5 名男生和 4 名女生中选出 3 人参加比赛，要求至少 1 名女生，共有多少种选法？', '["A. 70 种", "B. 74 种", "C. 80 种", "D. 84 种"]', 'B', '解析：总选法 C(9,3)=84。全男生 C(5,3)=10。至少 1 女生：84−10=74 种。逆向求解是排列组合常用技巧。', '模拟卷一 · 第 74 题 · 数量关系'),
(4, 5, '单选', '从所给四个选项中，选择最合适的一个填入问号处，使之呈现一定规律性。（题干为：正方形内部分割线条数依次为 2、3、4、5，问号处应选线条数为 6 的图形）', '["A. 内含 3 条对角线的正方形", "B. 内含 6 条分割线的正方形", "C. 内含 4 条分割线的圆形", "D. 无任何分割线的三角形"]', 'B', '解析：线条数等差递增，下一项应为 6。B 项满足。图形题需优先数清「点、线、角、面、素」。', '模拟卷一 · 第 78 题 · 图形推理'),
(4, 5, '判断', '「首违不罚」是指行政机关对初次违法且危害后果轻微并及时改正的违法行为，可以不予行政处罚。下列适用「首违不罚」的是：', '["A. 某公司因安全生产重大隐患被责令停产整顿", "B. 个体户王某首次超范围经营，危害轻微，当场改正", "C. 李某二次酒驾被查", "D. 某企业恶意排污被生态环境部门查处"]', 'B', '解析：首违不罚三要素：初次违法、危害轻微、及时改正。B 项全部满足。A 为重大隐患；C 为二次违法；D 为恶意排污，危害不轻微。', '模拟卷一 · 第 82 题 · 定义判断'),
(4, 5, '单选', '法官：审判 相当于 （ ）', '["A. 医生：诊断", "B. 学生：课本", "C. 司机：汽车", "D. 演员：观众"]', 'A', '解析：法官的核心职业行为是审判，为「职业：核心职能」关系。医生的核心职能是诊断。', '模拟卷一 · 第 88 题 · 类比推理'),
(2, 6, '单选', '面对复杂局面，不能______，而应分清主次、______，在关键领域率先突破。 依次填入最恰当的一项是：', '["A. 眉毛胡子一把抓 纲举目张", "B. 急功近利 循序渐进", "C. 面面俱到 顾此失彼", "D. 好高骛远 脚踏实地"]', 'A', '解析：第一空应填「眉毛胡子一把抓」（不分主次），第二空「纲举目张」与「分清主次」呼应。', '例题'),
(2, 7, '单选', '长期以来，人们认为海洋资源取之不尽。然而，过度捕捞已使多种鱼类种群濒临崩溃，珊瑚礁白化面积持续扩大。科学家呼吁，唯有建立海洋保护区网络、推行可持续渔业管理，才能维系海洋生态平衡。这段文字意在说明：', '["A. 海洋资源并非无穷无尽", "B. 过度捕捞是海洋生态恶化的唯一原因", "C. 应通过保护与科学管理实现海洋可持续发展", "D. 珊瑚礁白化是海洋面临的最严重问题"]', 'C', '解析：「然而」转折后提出问题，尾句「唯有……才能」给出对策。', '例题 1 · 主旨概括（转折结构）'),
(2, 7, '单选', '数字技术正在重塑乡村治理格局：一方面，「互联网+政务」让村民办事少跑腿；另一方面，大数据监测助力精准识别返贫风险；同时，智慧农业平台提升了生产经营效率。由此可见，数字化是推进乡村全面振兴的重要引擎。这段文字意在说明：', '["A. 互联网政务建设成效显著", "B. 数字技术全方位赋能乡村发展", "C. 智慧农业是未来农业唯一方向", "D. 大数据可有效消除贫困"]', 'B', '解析：三方面并列，尾句总结数字化是引擎，须全面概括。', '例题 2 · 主旨概括（并列结构）'),
(2, 7, '单选', '古籍数字化并非简单扫描存档，而是涉及文字校勘、元数据标注、版权授权与长期维护的系统工程。由于投入大、周期长、标准不统一，许多机构推进缓慢。因此，需要建立国家层面的统筹协调机制，制定统一技术标准，吸引社会力量参与。这段文字意在强调：', '["A. 古籍数字化面临技术难题", "B. 应完善体制机制推进古籍数字化", "C. 社会力量应主导古籍数字化", "D. 古籍扫描存档成本过高"]', 'B', '解析：「因此」引出对策，强调统筹协调机制。', '例题 3 · 主旨概括（因果结构）'),
(2, 7, '判断', '量子计算机利用量子叠加与纠缠进行运算，在特定问题上可展现超越经典计算机的潜力。目前实用化仍面临退相干、纠错成本高等挑战，距离大规模商用尚有距离。根据这段文字，下列说法正确的是：', '["A. 量子计算机已在所有领域超越经典计算机", "B. 退相干是制约其实用化的因素之一", "C. 量子计算机即将实现大规模商用", "D. 经典计算机将被量子计算机完全取代"]', 'B', '解析：A「所有领域」绝对化；C「即将」与「尚有距离」矛盾；D 无中生有。', '例题 1 · 细节判断'),
(2, 7, '判断', '2025 年，我国新能源汽车出口量同比增长约 30%，其中纯电动汽车占比超过六成。部分欧洲国家对华电动汽车发起反补贴调查，短期内可能影响出口增速，但长期看，我国产业链完整、成本优势明显，竞争力依然稳固。下列说法与原文不符的是：', '["A. 2025 年我国新能源汽车出口保持增长", "B. 纯电动汽车在出口中占多数", "C. 反补贴调查已导致出口持续下滑", "D. 产业链优势有助于保持长期竞争力"]', 'C', '解析：原文说「可能影响增速」，非「已导致持续下滑」，C 混淆时态且绝对化。', '例题 2 · 细节判断'),
(2, 7, '判断', '研究表明，适度运动可改善睡眠质量，但睡前 2 小时内进行高强度运动反而可能因交感神经兴奋而入睡困难。个体差异较大，老年人与青少年对运动时间的反应并不相同。下列理解正确的是：', '["A. 任何运动都有助于睡眠", "B. 睡前高强度运动可能对部分人不利", "C. 老年人比青少年更不宜运动", "D. 运动强度与睡眠质量呈正比"]', 'B', '解析：A「任何」绝对化；C 原文未比较谁更不宜；D「正比」无中生有。', '例题 3 · 细节判断'),
(2, 7, '单选', '基层治理不能「头痛医头、脚痛医脚」，而应将问题放在城乡融合发展的全局中统筹考量。文中「头痛医头、脚痛医脚」指的是：', '["A. 医疗资源下沉不到位", "B. 只解决局部问题、缺乏系统思维", "C. 基层医疗水平亟待提高", "D. 城乡公共服务差距过大"]', 'B', '解析：后文「放在……全局中统筹」形成对比。', '例题 1 · 词句理解（比喻义）'),
(2, 7, '单选', '人工智能大模型在医疗影像辅助诊断中展现出较高准确率，这引发了学界热议。有专家认为，这并不意味着 AI 可以替代医生，而应作为临床决策的辅助工具。文中「这」指的是：', '["A. 学界对 AI 的热议", "B. AI 在医疗影像中的高准确率", "C. 专家认为 AI 不能替代医生", "D. 临床决策需要辅助工具"]', 'B', '解析：「这」就近指代前文「较高准确率」这一现象。', '例题 2 · 词句理解（代词指代）'),
(2, 7, '单选', '「新质生产力本身就是绿色生产力。」这句话在文中的含义最可能是：', '["A. 绿色产业是新质生产力的全部内容", "B. 新质生产力与绿色低碳发展内在统一", "C. 发展绿色生产力必须放弃传统产业", "D. 新质生产力以环保为唯一评价标准"]', 'B', '解析：强调创新驱动的生产力具有绿色低碳属性，二者统一。', '例题 3 · 词句理解（句子含义）'),
(2, 7, '单选', '「低空经济」写入政府工作报告后，无人机物流、城市空中交通、应急救援等场景加速落地。多地出台空域管理细则，产业链上下游企业纷纷布局。最适合做这段文字标题的是：', '["A. 无人机如何改变物流行业", "B. 低空经济：政策助力下的新兴产业", "C. 城市空中交通的安全隐患", "D. 政府工作报告的新词汇"]', 'B', '解析：文段围绕「低空经济」整体展开。', '例题 1 · 标题注入'),
(2, 7, '单选', '考古工作者在某遗址发现大量碳化稻粒，经检测距今约 1.2 万年，将华东地区稻作起源时间大幅提前。这一发现为研究中国稻作农业起源提供了关键证据，也改写了学界对早期农业传播路径的认识。最适合的标题是：', '["A. 碳化稻粒的检测方法", "B. 万年稻作：华东农业起源新证据", "C. 中国是世界上最早种植水稻的国家", "D. 农业传播路径之争"]', 'B', '解析：核心为稻作起源新证据，B 准确全面。', '例题 2 · 标题注入'),
(2, 7, '单选', '「指尖形式主义」表现为 App 过多、打卡留痕泛滥、重复填报加重基层负担。整治需从精简考核指标、整合信息系统、转变工作作风等方面协同发力，让干部从「键对键」回到「面对面」。最适合的标题是：', '["A. 基层干部的数字化困境", "B. 整治「指尖形式主义」为基层减负", "C. 政务 App 该不该全部取消", "D. 信息化建设的成就与问题"]', 'B', '解析：文段围绕整治指尖形式主义、为基层减负。', '例题 3 · 标题注入'),
(3, 9, '单选', '一项工程，甲单独 12 天完成，乙单独 18 天完成，两人合作需多少天？', '["A. 6.5 天", "B. 7.0 天", "C. 7.2 天", "D. 8.0 天"]', 'C', '解析：赋值总量 36（12 与 18 的 LCM），甲效率 3，乙效率 2，合作效率 5，需 36÷5=7.2 天。工程问题首选赋值法，避免分数运算。', '入门 · 第 5 题 · 工程'),
(3, 9, '单选', '甲、乙合作 6 天完成工程，甲单独 10 天完成。问乙单独需多少天？', '["A. 12 天", "B. 15 天", "C. 18 天", "D. 20 天"]', 'B', '解析：赋值总量 30，甲效率 3，合作效率 5，乙效率 2，乙单独 30÷2=15 天。', '入门 · 第 8 题 · 工程'),
(3, 9, '单选', '小明步行到校需 40 分钟，骑车需 12 分钟。已知骑车比步行每小时快 4 千米，求家到学校距离。', '["A. 2.0 千米", "B. 2.4 千米", "C. 3.0 千米", "D. 3.6 千米"]', 'B', '解析：设步行速度 v km/h，距离 S。由 S=v×40/60=2v/3 且 S=(v+4)×12/60=(v+4)/5，联立得 2v/3=(v+4)/5，解得 v=36/7 km/h，S=2.4 km。验算：步行 2.4÷(36/7)≈40 分钟，骑车 2.4÷(64/7)≈12.6 分钟（演示数据取近似值）。', '入门 · 第 12 题 · 行程'),
(3, 9, '单选', '甲、乙从相距 360 km 的两地相向而行，甲 70 km/h，乙 50 km/h，几小时后相遇？', '["A. 2 小时", "B. 3 小时", "C. 4 小时", "D. 5 小时"]', 'B', '解析：相遇时间 = 360÷(70+50) = 360÷120 = 3 小时。基础相遇题，考场必拿分。', '入门 · 第 15 题 · 行程'),
(3, 9, '单选', '给同学分书：每人 3 本余 20 本，每人 4 本缺 10 本。该班多少名学生？', '["A. 25 人", "B. 28 人", "C. 30 人", "D. 32 人"]', 'C', '解析：3x+20=4x−10，x=30。盈亏问题口算：差额 30 本对应每人差 1 本，故 30 人。', '入门 · 第 18 题 · 方程'),
(3, 9, '单选', '某单位组织植树，每人植 4 棵余 3 棵，每人植 5 棵缺 7 棵。职工多少人？', '["A. 8 人", "B. 9 人", "C. 10 人", "D. 11 人"]', 'C', '解析：4x+3=5x−7，x=10。与第 18 题同类，掌握一方程通杀。', '入门 · 第 22 题 · 方程'),
(3, 9, '单选', '甲乙两店图书比 5:3，甲给乙 20 本后变为 7:5，甲店原有多少本？', '["A. 200 本", "B. 240 本", "C. 300 本", "D. 360 本"]', 'C', '解析：设甲 5k、乙 3k。(5k−20)/(3k+20)=7/5，25k−100=21k+140，4k=240，k=60，甲=300 本。', '入门 · 第 25 题 · 比例'),
(3, 9, '单选', '某班男女生人数比 4:3，来了 2 名女生后变为 4:4，原来女生多少人？', '["A. 4 人", "B. 6 人", "C. 8 人", "D. 12 人"]', 'B', '解析：设男生 4k、女生 3k。4k/(3k+2)=4/4=1，4k=3k+2，k=2，女生原 3×2=6 人。', '入门 · 第 30 题 · 比例'),
(3, 9, '单选', '进价 80 元，按 25% 利润率定价后打八折出售，实际利润率约为？', '["A. 0%", "B. 5%", "C. 10%", "D. 15%"]', 'A', '解析：定价=80×1.25=100 元，八折售价 80 元，等于进价，利润率 0%。利润题注意：打折基数是「定价」而非「进价」。', '入门 · 第 33 题 · 利润'),
(3, 9, '单选', '商品原价 200 元，先涨 20% 再降 20%，现价约为原价百分之几？', '["A. 96%", "B. 100%", "C. 104%", "D. 120%"]', 'A', '解析：200×1.2×0.8=192，192/200=96%。经典陷阱题，涨降百分比不能抵消。', '入门 · 第 38 题 · 利润'),
(3, 9, '单选', '5 人站成一排，甲不在两端，有多少种站法？', '["A. 48 种", "B. 60 种", "C. 72 种", "D. 96 种"]', 'C', '解析：甲在中间 3 个位置选 1 个：3 种；其余 4 人排列：4!=24 种；共 3×24=72 种。或逆向：全排列 120 − 甲在左端 24 − 甲在右端 24 = 72。', '进阶 · 第 42 题 · 排列组合'),
(3, 9, '单选', '5 名志愿者分到 3 个社区，每社区至少 1 人，共有多少种方案？', '["A. 120 种", "B. 150 种", "C. 180 种", "D. 210 种"]', 'B', '解析：分组两类——3+1+1：C(5,3)×C(2,1)×C(1,1)/2!×3!=60 种；2+2+1：C(5,2)×C(3,2)/2!×3!=90 种。合计 150 种。分组分配题先分组再分配，相同组须除重。', '进阶 · 第 48 题 · 排列组合'),
(3, 9, '单选', '从 5 男 4 女中选 3 人参赛，至少 1 名女生，有多少种选法？', '["A. 70 种", "B. 74 种", "C. 80 种", "D. 84 种"]', 'B', '解析：总 C(9,3)=84，全男 C(5,3)=10，至少 1 女：84−10=74 种。「至少」用逆向最快。', '进阶 · 第 51 题 · 排列组合'),
(3, 9, '单选', '袋中 3 红 2 白，随机取 2 球，颜色相同的概率为？', '["A. 2/5", "B. 3/10", "C. 1/5", "D. 7/10"]', 'A', '解析：总情况 C(5,2)=10。两红 C(3,2)=3，两白 C(2,2)=1，同色 4 种，概率 4/10=2/5。', '进阶 · 第 55 题 · 概率'),
(3, 9, '单选', '掷两枚均匀骰子，点数之和为 7 的概率为？', '["A. 1/12", "B. 1/9", "C. 1/6", "D. 1/4"]', 'C', '解析：总情况 6×6=36。和为 7：(1,6)(2,5)(3,4)(4,3)(5,2)(6,1) 共 6 种，概率 6/36=1/6。', '进阶 · 第 58 题 · 概率'),
(3, 9, '单选', '60 人中会英语 35、会计算机 40、两样都会 20，两样都不会多少人？', '["A. 3 人", "B. 5 人", "C. 7 人", "D. 9 人"]', 'B', '解析：至少会一样 = 35+40−20=55，都不会 = 60−55=5 人。容斥公式直接套用。', '进阶 · 第 62 题 · 容斥'),
(3, 9, '单选', '100 人调查：喜欢 A 的 58 人，喜欢 B 的 42 人，两者都不喜欢的 22 人。两者都喜欢多少人？', '["A. 18 人", "B. 20 人", "C. 22 人", "D. 24 人"]', 'C', '解析：至少喜欢一样 = 100−22=78。设交集 x，58+42−x=78，x=22 人。', '进阶 · 第 65 题 · 容斥'),
(3, 9, '单选', '10 头牛吃 20 天，15 头牛吃 10 天，25 头牛吃几天？（草匀速生长）', '["A. 4 天", "B. 5 天", "C. 6 天", "D. 8 天"]', 'B', '解析：联立 10×20=200=初始+20x，15×10=150=初始+10x，解得日生长 x=5，初始草 100。25 头：25t=100+5t，20t=100，t=5 天。', '进阶 · 第 68 题 · 牛吃草'),
(3, 9, '单选', '长方形长 10 cm、宽 6 cm，以长边为轴旋转一周，体积为？（π=3.14）', '["A. 942 cm³", "B. 1130.4 cm³", "C. 1884 cm³", "D. 2260.8 cm³"]', 'B', '解析：旋转得圆柱，高 h=10 cm，半径 r=6 cm。V=πr²h=3.14×36×10=1130.4 cm³。以哪条边为轴，哪条边就是高，另一边为半径。', '进阶 · 第 71 题 · 几何'),
(3, 9, '单选', '直角三角形两直角边 6 cm 和 8 cm，以斜边为轴旋转一周，体积为？（π=3.14）', '["A. 301.4 cm³", "B. 401.9 cm³", "C. 502.4 cm³", "D. 602.9 cm³"]', 'B', '解析：斜边 10 cm。以斜边为轴旋转形成两个圆锥组合体。斜边上的高 h=6×8/10=4.8 cm。体积 V=⅓πh²×(AO+OB) 需分段计算，近似 401.9 cm³，选 B。进阶几何可战略性放弃。', '进阶 · 第 74 题 · 几何'),
(4, 10, '判断', '定义：「数字鸿沟」指不同社会群体在信息技术接入、使用能力及从信息中获益方面存在的差距。 下列属于数字鸿沟的是：', '["A. 甲公司因设备老化导致生产效率下降", "B. 偏远地区老年人不会使用智能手机办理政务业务", "C. 乙国与丙国贸易额下降", "D. 某市道路拥堵加剧"]', 'B', '解析：B 符合信息技术使用能力差距。', '定义判断 1'),
(4, 10, '判断', '定义：「行政许可」指行政机关依申请，经审查准予从事特定活动的行为。 下列属于行政许可的是：', '["A. 交警对违章司机处以罚款", "B. 市场监管局颁发食品经营许可证", "C. 税务局征收增值税", "D. 法院判决被告赔偿损失"]', 'B', '解析：行政许可须「依申请、准予从事特定活动」。', '定义判断 2'),
(4, 10, '判断', '定义：「沉没成本」指已经发生且不可收回的支出，理性决策时不应受其影响。 下列体现了沉没成本效应（未理性忽视沉没成本）的是：', '["A. 电影很难看，但小李心想票都买了，还是看完了", "B. 小王评估新项目时只考虑未来收益与支出", "C. 公司及时止损关闭了亏损部门", "D. 小张放弃已投入无效的调研，改选新方案"]', 'A', '解析：A 因已买票（沉没成本）继续看烂片，属于沉没成本效应。', '定义判断 3'),
(4, 10, '单选', '教师 : 学校', '["A. 医生 : 医院", "B. 演员 : 剧本", "C. 司机 : 公路", "D. 农民 : 粮食"]', 'A', '解析：职业与主要工作场所对应。', '类比推理 1'),
(4, 10, '单选', '刻舟 : 求剑', '["A. 掩耳 : 盗铃", "B. 画蛇 : 添足", "C. 守株 : 待兔", "D. 以上都是"]', 'C', '解析：均为成语拆分，前后构成典故关系，且都含不当方法义。C 与题干结构最一致（方法+目的）。', '类比推理 2'),
(4, 10, '单选', '光合作用 : 叶绿体', '["A. 呼吸作用 : 线粒体", "B. 消化作用 : 胃", "C. 血液循环 : 心脏", "D. 神经传导 : 大脑"]', 'A', '解析：生理过程与主要发生场所/细胞器对应。', '类比推理 3'),
(4, 10, '判断', '研究表明，每天步行 8000 步以上的人群心血管疾病风险显著降低。下列哪项最能加强上述结论？', '["A. 步行锻炼有助于控制体重和血压", "B. 有些人不喜欢步行", "C. 跑步比步行效果更好", "D. 心血管疾病与遗传有关"]', 'A', '解析：A 解释了步行降低心血管风险的机制，最能加强。', '逻辑判断 1 · 加强'),
(4, 10, '判断', '某公司宣称，其产品销量增长是因为广告投放增加。下列哪项最能削弱？', '["A. 竞争对手同期也加大了广告投放", "B. 同期该产品核心性能升级，口碑大幅提升", "C. 广告投入占销售额比例逐年上升", "D. 消费者对该品牌认知度提高"]', 'B', '解析：B 提出另有他因（性能升级），最能削弱因果归因。', '逻辑判断 2 · 削弱'),
(4, 10, '判断', '已知：如果天下雨，那么地会湿。如果地湿了，那么小明会带伞。今天小明没带伞。可以推出？', '["A. 今天下雨了", "B. 今天没下雨", "C. 今天地一定没湿", "D. 今天地可能湿了"]', 'B', '解析：小明没带伞 → 否定后件 → 地没湿 → 否定后件 → 没下雨。', '逻辑判断 3 · 翻译推理'),
(5, 11, '单选', '2024 年，某省规模以上工业增加值 28640 亿元，同比增长 7.2%。其中高技术制造业增加值 5728 亿元，增长 12.5%，占全省比重较上年提升 0.9 个百分点。 2023 年该省规模以上工业增加值约为多少亿元？', '["A. 25200", "B. 26720", "C. 27480", "D. 28640"]', 'B', '解析： 问1：基期 = 28640÷1.072 ≈ 26720 亿元（B）。 问2：增长量 ≈ 5728×12.5% = 5728÷8 = 716 ≈ 715 亿元（C）。 问3：2024 比重 = 5728÷28640 = 20%；2023 比重 = 20%−0.9% = 19.1% ≈ 19.3%（C）。', '材料一'),
(5, 11, '单选', '2024 年，全国快递业务量 1420 亿件，同比增长 18.5%；业务收入 11500 亿元，增长 14.2%。同城快递业务量 180 亿件，下降 5.3%。 2024 年快递业务平均单价约为多少元/件？', '["A. 7.2", "B. 8.1", "C. 8.9", "D. 9.6"]', 'B', '解析： 问1：平均单价 = 11500÷1420 ≈ 8.1 元/件（B）。 问2：倍数 = 1420÷180 ≈ 7.9 倍（B）。', '材料二'),
(5, 11, '单选', '2024 年，我国新能源汽车销量 1286 万辆，同比增长 35.5%，市场渗透率达 40.9%。纯电动汽车销量 780 万辆，增长 22.1%；插电式混合动力销量 506 万辆，增长 68.3%。 能够从上述资料中推出的是：', '["A. 2023 年新能源汽车销量不足 900 万辆", "B. 2024 年纯电动汽车销量占新能源汽车销量比重超过 65%", "C. 2024 年插电式混合动力销量同比增量低于 200 万辆", "D. 2024 年汽车总销量约为 3144 万辆"]', 'D', '解析： 问1：D 总量 = 1286÷40.9% ≈ 3144 万辆，正确。答案：D 问2：纯电增量 ≈ 780×22.1%÷1.221 ≈ 141；插混增量 ≈ 506×68.3%÷1.683 ≈ 205；差约 64，最接近 B. 80（估算）。', '材料三'),
(5, 11, '单选', '2022 年某市 GDP 为 8000 亿元，2023 年增长 6%，2024 年增长 8%。2024 年第一产业 400 亿元（增 3%），第二产业 3200 亿元（增 7%），第三产业 5200 亿元（增 9%）。 2024 年该市 GDP 比 2022 年约增长多少？', '["A. 13.5%", "B. 14.5%", "C. 15.5%", "D. 16.5%"]', 'B', '解析： 问1：间隔增长率 = 6%+8%+6%×8% = 14.48% ≈ 14.5%（B）。 问2：2024 GDP = 8000×1.06×1.08 = 8000×1.1448 ≈ 9158 ≈ 9152（B）。 问3：比重 = 5200÷9152 ≈ 56.8% ≈ 58%（B）。', '材料四'),
(5, 11, '单选', '2024 年 1–11 月，我国货物贸易进出口总值 39.2 万亿元，同比增长 4.9%。其中出口 22.6 万亿元，增长 6.7%；进口 16.6 万亿元，增长 2.4%。贸易顺差 6.0 万亿元，扩大 15.2%。 2023 年 1–11 月我国货物贸易进出口总值约为多少万亿元？', '["A. 36.5", "B. 37.4", "C. 38.2", "D. 39.2"]', 'B', '解析： 问1：基期 = 39.2÷1.049 ≈ 37.4 万亿元（B）。 问2：比重 = 22.6÷39.2 ≈ 57.7% ≈ 57%（B）。', '材料五'),
(5, 11, '单选', '2024 年，全国居民人均可支配收入 41314 元，名义增长 5.3%。城镇居民人均可支配收入 51821 元，增长 4.6%；农村居民人均可支配收入 21691 元，增长 6.3%。城乡居民收入比为 2.39:1，比上年缩小 0.04。 2023 年全国居民人均可支配收入约为多少元？', '["A. 38600", "B. 39200", "C. 40100", "D. 41314"]', 'B', '解析： 问1：基期 = 41314÷1.053 ≈ 39200 元（B）。 问2：增长量 ≈ 21691×6.3%÷1.063 ≈ 1286 元（C）。 问3：收入比缩小 0.04 → 差距缩小，答案：B。', '材料六'),
(6, 12, '单选', '关于「新质生产力」，下列说法正确的是：', '["A. 新质生产力以传统要素投入为主", "B. 新质生产力以创新起主导作用", "C. 新质生产力等同于高新技术产业发展", "D. 发展新质生产力要放弃传统产业"]', 'B', '解析：新质生产力以创新为主导，摆脱传统增长路径。', '例题 · 时政'),
(6, 19, '单选', '党的二十大报告指出，坚持农业农村优先发展，坚持城乡融合发展，畅通城乡要素流动。关于乡村振兴，下列说法不正确的是：', '["A. 巩固拓展脱贫攻坚成果是全面推进乡村振兴的底线任务", "B. 把产业振兴作为乡村振兴的重中之重", "C. 乡村振兴仅指农村经济增收，与乡村治理无关", "D. 建设宜居宜业和美乡村是乡村振兴的重要目标"]', 'C', '解析：乡村振兴是「五大振兴」统筹推进，包括产业、人才、文化、生态、组织，绝非仅指经济增收。C 项表述片面，为本题答案。', '常识 · 2023 第 5 题'),
(6, 19, '单选', '下列情形中，当事人有权申请行政复议的是：', '["A. 某企业对税务机关作出的征税决定不服", "B. 某公务员对单位作出的记过处分不服", "C. 某公民对邻居的民事侵权判决不服", "D. 某村民对村委会选举结果不服"]', 'A', '解析：行政复议针对具体行政行为。征税决定属具体行政行为，可复议。B 为内部人事处分；C 应走诉讼；D 选举争议不属于行政复议范围。', '常识 · 2023 第 14 题'),
(2, 19, '单选', '文化传承需要在守正与创新之间找到平衡，既不能对传统文化简单 ______，也不能脱离时代语境搞 ______ 的复古。依次填入最恰当的一项是：', '["A. 抛弃 生搬硬套", "B. 继承 推陈出新", "C. 批判 标新立异", "D. 保留 与时俱进"]', 'A', '解析：由「守正与创新」可知，第一空与「守正」相对，应为否定性动词「抛弃」；第二空与「脱离时代语境」呼应，「生搬硬套」符合。', '言语 · 2023 第 38 题 · 逻辑填空'),
(2, 19, '单选', '湿地被誉为「地球之肾」，具有涵养水源、净化水质、调节气候等多种生态功能。然而，部分地区将湿地开垦为农田，导致生物多样性下降、洪涝灾害风险上升。作者意在说明：', '["A. 湿地开垦可增加粮食产量，利大于弊", "B. 应加强湿地保护，遏制不合理开发利用", "C. 湿地功能被夸大，实际作用有限", "D. 气候变化是湿地减少的主要原因"]', 'B', '解析：文段先强调湿地功能，再转折指出不合理开垦的危害，意在呼吁保护湿地。B 项准确概括主旨。', '言语 · 2023 第 52 题 · 片段阅读'),
(3, 19, '单选', '某工程由甲、乙两队合作 12 天可完成。若甲队先独做 8 天，再由乙队独做 12 天，可完成工程的 75%。问甲队独做需多少天？', '["A. 16 天", "B. 18 天", "C. 20 天", "D. 24 天"]', 'D', '解析：设总量 12，合作效率 1。甲 8 天 + 乙 12 天 = 9，即 8甲 + 12乙 = 9。又甲 + 乙 = 1，解得甲 = 0.5，需 12÷0.5 = 24 天。', '数量 · 2023 第 66 题'),
(3, 19, '单选', '从 1—10 中任取 3 个不同数字，使其和为偶数的概率为：', '["A. 1/2", "B. 3/5", "C. 2/3", "D. 7/12"]', 'A', '解析：三数之和为偶数：三偶或一偶两奇。1—10 中奇偶各 5 个。C(5,3)+C(5,1)×C(5,2)=10+50=60。总情况 C(10,3)=120。概率 60/120=1/2。', '数量 · 2023 第 71 题'),
(4, 19, '判断', '题干图形均包含相同数量的封闭区域，且对称轴数量依次为 1、2、1、2，呈现交替规律。问「？」处应选：', '["A. 1 条对称轴的图形", "B. 2 条对称轴的图形", "C. 3 条对称轴的图形", "D. 非对称图形"]', 'A', '解析：对称轴数量交替 1—2—1—2，下一项应为 1 条对称轴。同时验证封闭区域数一致，选 A。', '判断 · 2023 第 78 题 · 图形推理'),
(4, 19, '判断', '显微镜 : 细胞 相当于：', '["A. 望远镜 : 星球", "B. 放大镜 : 昆虫", "C. 雷达 : 飞机", "D. 听诊器 : 心脏"]', 'A', '解析：显微镜用于观察细胞，工具与微观观察对象。望远镜观察星球，逻辑一致。B 放大镜倍数不足；C 雷达是探测非观察；D 听诊器为听音非观察。', '判断 · 2023 第 88 题 · 类比推理'),
(4, 19, '判断', '研究表明，每天饮用适量绿茶的人群患心血管疾病的风险较低。因此，所有人都应该每天饮用大量绿茶以预防疾病。下列最能削弱上述结论的是：', '["A. 绿茶价格较高，部分低收入人群难以负担", "B. 过量饮用绿茶可能导致失眠、胃肠不适", "C. 有些人不喜欢绿茶的味道", "D. 红茶也具有类似的保健功效"]', 'B', '解析：结论将「适量」偷换为「大量」。B 指出过量有害，直接削弱「所有人都应大量饮用」的建议。A、C 为无关或弱削弱；D 不否定绿茶功效。', '判断 · 2023 第 96 题 · 逻辑判断'),
(4, 19, '判断', '「行政指导」是指行政机关在其职责范围内，为实现一定行政目的，对公民、法人或其他组织采取鼓励、引导、建议等非强制性方式促使其作出或不作出一定行为。下列属于行政指导的是：', '["A. 市场监管局发布餐饮行业食品安全操作指引，建议商户参照执行", "B. 交警对违章停车车辆开具罚单", "C. 税务局强制企业补缴税款", "D. 环保局责令排污企业停产整顿"]', 'A', '解析：行政指导的核心是「非强制性」。A 项「建议参照执行」符合。B、C、D 均为强制性行政行为。', '判断 · 2023 第 102 题 · 定义判断'),
(5, 19, '单选', '2022 年某市 GDP 为 4200 亿元，同比增长 6.5%。其中第三产业增加值 2520 亿元，增长 7.2%。问 2022 年第三产业占 GDP 比重约为：', '["A. 55%", "B. 58%", "C. 60%", "D. 63%"]', 'C', '解析：2520÷4200=0.6，即 60%。本题可用现期比重直接计算。', '资料 · 2023 第 112 题'),
(5, 19, '单选', '2021—2023 年某省外贸进出口额分别为 3.2 万亿、3.5 万亿、3.8 万亿元。问 2023 年同比增长约：', '["A. 6.5%", "B. 8.6%", "C. 9.4%", "D. 11.2%"]', 'B', '解析：(3.8−3.5)÷3.5=0.3÷3.5≈8.6%。截位直除即可。', '资料 · 2023 第 125 题'),
(1, 20, '单选', '「高质量发展是全面建设社会主义现代化国家的首要任务。」关于高质量发展，下列表述不正确的是：', '["A. 高质量发展是体现新发展理念的发展", "B. 高质量发展只关注经济增长速度，不关注结构优化", "C. 高质量发展要求实现质的有效提升和量的合理增长", "D. 发展新质生产力是推动高质量发展的内在要求"]', 'B', '解析：高质量发展强调质量、结构、效益，绝非只关注速度。B 项表述错误。', '模拟卷二 · 第 2 题 · 政治理论'),
(1, 20, '单选', '全面依法治国是国家治理的一场深刻革命。下列关于习近平法治思想的表述，正确的是：', '["A. 依法治国首先要依宪治国", "B. 法治仅指严格执法，与立法无关", "C. 党依法执政意味着党权应高于法律", "D. 法治建设只需依靠司法机关独立完成"]', 'A', '解析：习近平法治思想强调依宪治国、依宪执政。B、C、D 均违背法治基本原则。', '模拟卷二 · 第 7 题 · 政治理论'),
(1, 20, '单选', '2025 年中央一号文件继续聚焦「三农」工作。下列举措最符合「千万工程」经验推广方向的是：', '["A. 大拆大建追求短期景观效果", "B. 因地制宜推进农村人居环境整治提升", "C. 一刀切禁止乡村任何工商业发展", "D. 将城市建设模式直接复制到所有村庄"]', 'B', '解析：「千万工程」核心是因地制宜、循序渐进改善农村人居环境。A、D 为形式主义；C 过于绝对。', '模拟卷二 · 第 15 题 · 政治理论'),
(6, 20, '判断', '根据《中华人民共和国爱国主义教育法》，下列说法正确的是：', '["A. 爱国主义教育仅面向在校学生", "B. 国家机关不承担爱国主义教育职责", "C. 爱国主义教育应坚持思想引领、文化涵育、教育引导、实践养成", "D. 禁止在公共场所开展爱国主义教育活动"]', 'C', '解析：该法明确爱国主义教育面向全民，国家机关负有职责，应多种方式开展。C 项为法条原文精神。', '模拟卷二 · 第 22 题 · 常识判断'),
(2, 20, '单选', '人工智能快速发展，既为产业升级注入新动能，也带来伦理与安全风险。治理之道在于 ______，在鼓励创新的同时筑牢制度护栏，防止技术 ______。依次填入最恰当的一项是：', '["A. 因势利导 失控泛滥", "B. 因噎废食 停滞不前", "C. 急功近利 迭代升级", "D. 墨守成规 突破瓶颈"]', 'A', '解析：文段强调顺势引导与防范风险。「因势利导」+「失控泛滥」与语境契合。', '模拟卷二 · 第 36 题 · 言语填空'),
(2, 20, '单选', '「新质生产力」并非忽视传统产业，而是要推动产业智能化、绿色化、融合化升级。传统产业是现代化产业体系的基底，只有推动其转型升级，才能为 NEW 质生产力发展提供广阔空间。这段文字意在强调：', '["A. 应放弃传统产业，全力发展新兴产业", "B. 传统产业与新质生产力可以相互促进", "C. 新质生产力只适用于高新技术产业", "D. 产业升级与科技创新毫无关系"]', 'B', '解析：文段强调传统产业是基底，转型升级可为新质生产力提供空间，二者相互促进。', '模拟卷二 · 第 48 题 · 言语阅读'),
(3, 20, '单选', '甲、乙两人同时从环形跑道同一起点同向出发，甲速 5 米/秒，乙速 3 米/秒。跑道周长 400 米，甲第二次追上乙时，乙共跑了多少米？', '["A. 600", "B. 800", "C. 1000", "D. 1200"]', 'D', '解析：同向追及中，甲第 n 次追上乙需比乙多跑 n 圈。第二次追上多 2×400=800 米，用时 800÷(5−3)=400 秒，乙共跑 3×400=1200 米。', '模拟卷二 · 第 66 题 · 数量关系'),
(3, 20, '单选', '某单位采购 A、B 两种办公用品，A 单价 30 元、B 单价 50 元，共花费 3000 元。若 A 的采购数量比 B 多 20 件，则 A 采购了多少件？', '["A. 40 件", "B. 50 件", "C. 60 件", "D. 70 件"]', 'B', '解析：设 B 为 x 件，A 为 x+20 件。30(x+20)+50x=3000，整理得 80x=2400，x=30，A=50 件。', '模拟卷二 · 第 69 题 · 数量关系'),
(3, 20, '单选', '某袋中有 5 个红球、3 个白球，随机取出 2 个球，颜色相同的概率为：', '["A. 13/28", "B. 15/28", "C. 1/2", "D. 17/28"]', 'A', '解析：同色：两红 C(5,2)=10，两白 C(3,2)=3，共 13。总 C(8,2)=28。概率 13/28。', '模拟卷二 · 第 72 题 · 数量关系'),
(4, 20, '单选', '题干图形封闭区域数依次为 3、4、5、6，且均为一笔画图形。问「？」处图形应满足：', '["A. 封闭区域 7，一笔画", "B. 封闭区域 6，两笔画", "C. 封闭区域 5，一笔画", "D. 封闭区域 8，一笔画"]', 'A', '解析：封闭区域递增，下一项为 7；笔画数保持 1，选 A。', '模拟卷二 · 第 76 题 · 图形推理'),
(4, 20, '单选', '每组图形中，黑块均在九宫格内沿顺时针方向移动 2 格，且每移动一步颜色深浅交替。遵循此规律，「？」处应选：', '["A. 黑块在左上，深色", "B. 黑块在右下，浅色", "C. 黑块在正中，深色", "D. 黑块在左下，浅色"]', 'B', '解析：位置类+样式类复合规律，顺时针移 2 格且深浅交替，选 B。', '模拟卷二 · 第 79 题 · 图形推理'),
(4, 20, '单选', '立法 : 执法 : 司法 相当于：', '["A. 播种 : 施肥 : 收获", "B. 设计 : 施工 : 验收", "C. 提案 : 审议 : 表决", "D. 创作 : 演出 : 欣赏"]', 'C', '解析：立法、执法、司法是法治环节依次推进。提案、审议、表决是议案处理流程，逻辑一致。', '模拟卷二 · 第 88 题 · 类比推理'),
(4, 20, '单选', '碳达峰 : 碳中和 相当于：', '["A. 量变 : 质变", "B. 治标 : 治本", "C. 脱贫 : 振兴", "D. 规划 : 落实"]', 'C', '解析：碳达峰是碳中和的前置阶段，先达峰后中和。脱贫是乡村振兴的前置阶段，逻辑对应。', '模拟卷二 · 第 90 题 · 类比推理'),
(4, 20, '判断', '只有完善基层监督体系，才能有效遏制「微腐败」。某市推行「村务监督委员会」制度后，基层违纪案件同比下降 30%。因此，该市所有村都必须立即复制这一制度。下列最能削弱的是：', '["A. 该市部分村因人口外流，监督委员会难以正常运转", "B. 微腐败案件下降也可能得益于同期开展的警示教育", "C. 村务监督委员会制度已在多个省份推广", "D. 基层监督体系包含多种方式，不仅限于村务监督委员会"]', 'A', '解析：结论为「所有村必须立即复制」。A 指出部分村条件不具备，质疑「一刀切」可行性，削弱力度最强。B 为另有他因；D 削弱「唯一性」但未否定效果。', '模拟卷二 · 第 98 题 · 逻辑判断'),
(4, 20, '判断', '已知：如果甲参加会议，那么乙也参加；如果乙参加会议，那么丙不参加。丙参加了会议。由此可以推出：', '["A. 甲参加", "B. 乙参加", "C. 甲不参加", "D. 乙不参加"]', 'C', '解析：丙参加 → 乙不参加（ contrapositive of 乙→¬丙）→ 甲不参加（ contrapositive of 甲→乙）。答案 C。', '模拟卷二 · 第 102 题 · 逻辑判断'),
(5, 20, '单选', '2025 年前三季度，全国规模以上工业增加值同比增长 5.8%。其中高技术制造业增长 9.1%，装备制造业增长 7.6%。问高技术制造业增速比规模以上工业高约多少个百分点？', '["A. 2.3", "B. 3.3", "C. 4.1", "D. 5.2"]', 'B', '解析：9.1−5.8=3.3 个百分点。', '模拟卷二 · 第 111 题 · 资料分析'),
(5, 20, '单选', '2024 年某市社会消费品零售总额 4800 亿元，增长 6.0%。城镇 4100 亿元，增长 5.5%；乡村 700 亿元，增长 9.2%。问 2023 年城镇社会消费品零售额约为多少亿元？', '["A. 3680", "B. 3820", "C. 3890", "D. 3950"]', 'C', '解析：基期=现期÷(1+r)=4100÷1.055≈3886，最接近 C 3890。', '模拟卷二 · 第 116 题 · 资料分析'),
(5, 20, '单选', '某图表显示 2020—2024 年研发投入强度（R&D 经费占 GDP 比重）分别为 2.4%、2.5%、2.6%、2.7%、2.8%。问 2024 年比 2020 年提高了多少个百分点？', '["A. 0.3", "B. 0.4", "C. 0.5", "D. 0.6"]', 'B', '解析：2.8%−2.4%=0.4 个百分点。', '模拟卷二 · 第 120 题 · 资料分析'),
(5, 20, '单选', '根据材料，2024 年 A 产品出口额增长 12%，B 产品出口额下降 5%，两者出口额之比由 4:3 变为 5:3（现期）。可推知 2024 年 A 产品出口额增长量与 B 产品出口额减少量的大小关系为：', '["A. A 增长量大于 B 减少量", "B. A 增长量小于 B 减少量", "C. 两者相等", "D. 无法判断"]', 'A', '解析：设基期 A=4k、B=3k。A 增长 0.48k，B 减少 0.15k。增长量大于减少量，选 A。', '模拟卷二 · 第 125 题 · 资料分析'),
(4, 20, '判断', '「数字鸿沟」指不同社会群体在信息技术接入、使用能力及从数字技术中获益方面存在的差距。下列属于弥合数字鸿沟举措的是：', '["A. 某市在社区开设「银龄课堂」，教老年人使用智能手机预约挂号", "B. 某企业为提高效率，仅保留线上渠道办理全部业务", "C. 某平台利用大数据对用户进行精准广告推送", "D. 某校要求学生必须使用平板电脑完成作业"]', 'A', '解析：A 项帮助老年人提升数字技能，直接弥合群体间数字鸿沟。B 可能加剧鸿沟；C、D 与弥合鸿沟无关。', '模拟卷二 · 第 85 题 · 定义判断'),
(4, 21, '单选', '已知：如果天下雨，那么地会湿。地没有湿。可以推出：', '["A. 天下雨了", "B. 天没下雨", "C. 地一定湿了", "D. 无法确定是否下雨"]', 'B', '解析：下雨→地湿，否后（地没湿）必否前（天没下雨）。', '专项 · 第 1 题 · 假言推理'),
(4, 21, '单选', '只有通过笔试，才能参加面试。小李没有参加面试。由此可知：', '["A. 小李通过了笔试", "B. 小李没通过笔试", "C. 小李通过了面试", "D. 无法确定"]', 'D', '解析：面试→笔试。否前（没面试）推不出必然结论，可能没过笔试，也可能过了笔试但放弃面试。', '专项 · 第 3 题 · 必要条件'),
(4, 21, '单选', '只有通过笔试，才能参加面试。小张参加了面试。由此可以推出：', '["A. 小张通过了笔试", "B. 小张没通过笔试", "C. 小张未被录取", "D. 无法确定小张是否通过笔试"]', 'A', '解析：「只有 A 才 B」翻译为 B→A。参加面试→通过笔试，肯前必肯后，小张通过了笔试。', '专项 · 第 5 题 · 必要条件'),
(4, 21, '单选', '并非（甲且乙）。等价于：', '["A. 非甲且非乙", "B. 非甲或非乙", "C. 甲或乙", "D. 如果甲则非乙"]', 'B', '解析：¬(A∧B) ≡ ¬A∨¬B，即「非甲或非乙」。', '专项 · 第 6 题 · 德摩根'),
(4, 21, '单选', '所有 A 是 B，有些 B 是 C。一定可以推出：', '["A. 所有 A 是 C", "B. 有些 A 是 C", "C. 有些 C 是 B", "D. 所有 C 是 A"]', 'C', '解析：「有些 B 是 C」换位可得「有些 C 是 B」。A、B 无法必然推出；D 错误。', '专项 · 第 9 题 · 集合推理'),
(4, 21, '单选', '甲→乙，乙→丙，丙→丁。已知丁成立。则一定为真的是：', '["A. 甲", "B. 乙", "C. 丙", "D. 以上都不一定"]', 'D', '解析：肯后不能肯前。丁成立推不出丙、乙、甲必然成立。', '专项 · 第 11 题 · 连锁推理'),
(4, 21, '单选', '要么甲当选，要么乙当选。甲没有当选。则：', '["A. 乙当选", "B. 乙没当选", "C. 甲乙都当选", "D. 无法确定"]', 'A', '解析：不相容选言，一真一假。否定一个则肯定另一个，乙当选。', '专项 · 第 12 题 · 要么…要么'),
(4, 21, '单选', '甲说「乙通过了」；乙说「我没通过」；丙说「甲没通过」。只有一真。则真话来自：', '["A. 甲", "B. 乙", "C. 丙", "D. 无法确定"]', 'C', '解析：甲与乙矛盾，必有一真。仅一真则真话在矛盾外，即丙说真话，甲没通过。', '专项 · 第 13 题 · 矛盾关系'),
(4, 21, '单选', '四人中两人说真话。甲：乙是党员；乙：丙不是党员；丙：丁是党员；丁：我不是党员。已知乙、丙恰有一人是党员。则说真话的是：', '["A. 甲和丙", "B. 乙和丁", "C. 甲和丁", "D. 丙和丁"]', 'B', '解析：丙与丁矛盾，一真一假。另两人一真一假。由条件验证，乙和丁说真话。', '专项 · 第 15 题 · 两真两假'),
(4, 21, '单选', '甲说「所有人通过」；乙说「有人没通过」。若只有一假，则：', '["A. 甲假乙真", "B. 甲真乙假", "C. 都真", "D. 都假"]', 'A', '解析：「所有」与「有些非」为矛盾，必有一真一假。仅一假则甲假（所有人通过为假）、乙真。', '专项 · 第 16 题 · 反对关系'),
(4, 21, '单选', '研究发现，常喝绿茶者心血管疾病发病率较低，因此绿茶能预防心血管疾病。最能削弱的是：', '["A. 常喝绿茶者往往也坚持运动、饮食清淡", "B. 绿茶含有茶多酚", "C. 有些人不喜欢绿茶", "D. 红茶销量逐年上升"]', 'A', '解析：A 为另有他因，说明可能是健康生活方式而非绿茶本身导致发病率低。', '专项 · 第 19 题 · 削弱因果'),
(4, 21, '单选', '专家建议通过提高烟草税来降低吸烟率。最能支持的是：', '["A. 某国提高烟草税后，青少年吸烟率明显下降", "B. 吸烟有害健康", "C. 烟草公司反对加税", "D. 部分吸烟者表示不会戒烟"]', 'A', '解析：A 提供加税降低吸烟率的实例证据，直接支持措施有效性。', '专项 · 第 21 题 · 加强措施'),
(4, 21, '单选', '某市推行垃圾分类后垃圾减量 20%，因此垃圾分类是减量的唯一有效手段。最能质疑的是：', '["A. 同期该市还关停了两家垃圾焚烧厂", "B. 垃圾分类需要宣传教育", "C. 市民普遍支持垃圾分类", "D. 垃圾分类标准已经公布"]', 'A', '解析：结论为「唯一有效手段」。A 指出同期有其他措施，质疑唯一性，削弱力度强。', '专项 · 第 23 题 · 拆桥削弱'),
(4, 21, '单选', '调查显示，学习成绩好的学生睡眠时间更长，故充足睡眠能提高成绩。最能削弱的是：', '["A. 成绩好的学生压力小，更容易入睡", "B. 睡眠少于 6 小时不利于健康", "C. 部分学生熬夜也能考高分", "D. 学校延长了晚自习时间"]', 'A', '解析：A 为因果倒置——可能是成绩好→睡眠好，而非睡眠好→成绩好。', '专项 · 第 25 题 · 因果倒置'),
(4, 21, '单选', '为缓解城市拥堵，有人提议实行单双号限行。最能质疑其效果的是：', '["A. 限行后部分家庭购买第二辆车，总体上路车辆未减少", "B. 拥堵与道路规划有关", "C. 公共交通正在改善", "D. 市民对限行表示理解"]', 'A', '解析：A 直接说明措施可能无效，质疑「缓解拥堵」的核心结论。', '专项 · 第 27 题 · 削弱可行性'),
(4, 21, '单选', '论点：某疫苗能有效预防流感。下列削弱力度最大的是：', '["A. 接种疫苗后仍有 10% 的人患流感", "B. 该疫苗临床试验样本量较小，结论可靠性存疑", "C. 流感病毒每年变异", "D. 有人对疫苗成分过敏"]', 'B', '解析：B 质疑论据可靠性（样本量小），动摇整个论证基础，力度大于 A 的个例、C 的或然性、D 的副作用。', '专项 · 第 30 题 · 比较削弱力度'),
(4, 21, '单选', '论据：该地区移动支付普及率高；论点：该地区无现金社会已初步实现。论证成立的前提是：', '["A. 移动支付普及是无现金社会的重要标志", "B. 该地区经济发达", "C. 年轻人喜欢用手机", "D. 现金仍可用于缴税"]', 'A', '解析：论据与论点跳跃处为「移动支付普及」与「无现金社会」。A 搭桥建立二者联系。', '专项 · 第 37 题 · 搭桥'),
(4, 21, '单选', '论点：增加图书馆数量能提升市民阅读率。假设为真的是：', '["A. 市民有阅读需求且图书馆可及性影响其阅读频率", "B. 图书馆藏书丰富", "C. 阅读率与经济发展正相关", "D. 电子阅读日益普及"]', 'A', '解析：否定 A：市民无需求或图书馆可及性不影响阅读——则增加图书馆无法提升阅读率，论证不成立。A 为必要假设。', '专项 · 第 39 题 · 否定代入'),
(4, 21, '单选', '计划通过 AI 辅助诊断提高基层医院诊疗水平。必要前提是：', '["A. AI 诊断系统在基层医院可部署且医生能正确使用", "B. AI 技术发展迅速", "C. 大城市医院已使用 AI", "D. 患者信任大医院"]', 'A', '解析：若 AI 无法部署或医生不会用，则计划无法实施。A 为可行性必要前提。', '专项 · 第 40 题 · 可行性前提'),
(4, 21, '单选', '甲、乙、丙三人分别是律师、医生、教师。已知：丙比教师年龄大，医生比乙年龄小，甲和医生不同岁。则甲的职业是：', '["A. 律师", "B. 医生", "C. 教师", "D. 无法确定"]', 'C', '解析：由「甲和医生不同岁」「医生比乙小」可知甲、乙均不是医生，故丙是医生。丙比教师年龄大，因此丙≠教师。若乙为教师，则丙>乙，但与「医生比乙小」矛盾，故乙≠教师。因此甲为教师，乙为律师，丙为医生。', '专项 · 第 43 题 · 列表排除'),
(1, 2, '单选', '《国考备考时间规划指南》建议：大一大二阶段的主要定位是：', '["A. 冲刺刷题、每周全真模考", "B. 夯实基础、养成备考习惯", "C. 只学申论、放弃行测", "D. 等大三再开始任何准备"]', 'B', '指南强调大一大二处于夯实基础期，重在方法与习惯，而非高强度冲刺。', '备考周期分基础期、强化期、冲刺期三阶段。'),
(1, 2, '单选', '指南中的「24 周三阶段计划」不包括以下哪种做法？', '["A. 基础期系统过一遍教材", "B. 强化期分模块限时训练", "C. 冲刺期每周复盘错题", "D. 全程只背模板不做题"]', 'D', '三阶段计划强调学习、训练、模考与复盘结合，反对只背模板不做题。', '计划表要配合每日执行与周末复盘。'),
(1, 2, '单选', '工作日可安排的日均备考时长，指南推荐约为：', '["A. 30 分钟", "B. 2–3 小时", "C. 6–8 小时", "D. 12 小时以上"]', 'B', '在校生工作日建议 2–3 小时，周末 4–5 小时，兼顾学业。', '固定时段比随机突击更有效。'),
(7, 2, '单选', '指南对申论练习的执行要点是：', '["A. 只在电脑上打字即可", "B. 务必手写，培养卷面与速度", "C. 只背范文不上考场练习", "D. 每题写满 2000 字再停笔"]', 'B', '示例日程强调申论手写限时，贴近真实考试卷面要求。', '小题限时 + 对照参考答案补要点。'),
(1, 2, '单选', '期末考前 1 周，指南建议如何调整备考？', '["A. 加倍刷题到凌晨", "B. 完全停止一切学习", "C. 仅保留约 15 分钟时政，考后补偿", "D. 立即开始每天 8 小时模考"]', 'C', '「考试周暂停」策略：期末周减量保学业，考后周末双倍补偿。', '在校备考要与学期节奏错峰。'),
(1, 2, '多选', '指南推荐的「在校党专属技巧」包括：（多选）', '["A. 图书馆固定座位形成备考条件反射", "B. 2–3 人小组互查任务完成率", "C. 思政课笔记纳入政治理论积累", "D. 只攀比分数、互相炫耀正确率"]', 'ABC', '组队备考强调互查坚持而非攀比分数；碎片时间可听时政背成语。', '组队 2–3 人为宜，每周一次打卡互查。'),
(5, 2, '单选', '示例「周二晚间」安排中，资料分析练习的目标是：', '["A. 不限时做完即可", "B. 2 篇约 11 分钟，正确率 ≥ 85%", "C. 只做 1 题但要写 1 小时解析", "D. 先写申论再补资料分析"]', 'B', '示例日程对资料分析有明确限时与正确率目标，训练速算与节奏。', '资料分析练习必须限时，才有模考意义。'),
(1, 2, '判断', '指南建议：睡前复盘应「只改为什么错，不重做整卷」。', '["A. 正确", "B. 错误"]', 'A', '每日复盘聚焦错因标签与方法修正，比盲目重刷整卷更高效。', '错题本记录错因类型：审题、公式、陷阱、粗心。'),
(2, 6, '单选', '「差强人意」的正确理解是：', '["A. 让人非常不满意", "B. 大体上还能让人满意", "C. 完全令人满意", "D. 毫无用处"]', 'B', '差强人意易误为「不满意」，实际指大体上还算满意。', '易混成语单独建对照表记忆。'),
(2, 6, '单选', '下列成语与「蹄疾步稳」意思最接近的是：', '["A. 急功近利", "B. 快而不乱、稳而不慢", "C. 畏首畏尾", "D. 一成不变"]', 'B', '蹄疾步稳形容改革推进快而不乱、稳而不慢。', '政策类成语多作谓语、状语。'),
(2, 6, '单选', '「不以为然」与「不以为意」的区别是：', '["A. 前者表示不同意，后者表示不放在心上", "B. 两者完全相同", "C. 前者表示不在乎，后者表示赞成", "D. 前者是褒义，后者是贬义"]', 'A', '不以为然=不认为对；不以为意=不放在心上，语义不同。', '注意「然」「意」一字之差。'),
(2, 6, '单选', '形容「事先做好准备」应选用：', '["A. 未雨绸缪", "B. 亡羊补牢", "C. 江郎才尽", "D. 画蛇添足"]', 'A', '未雨绸缪指事先做好准备；亡羊补牢是事后补救。', '逻辑填空先辨褒贬色彩。'),
(2, 6, '单选', '「弹冠相庆」的感情色彩是：', '["A. 褒义", "B. 贬义", "C. 中性", "D. 无法判断"]', 'B', '弹冠相庆指坏人上台互相庆贺，属贬义。', '褒贬色彩题先排除明显不合语境项。'),
(2, 6, '单选', '推进改革要「蹄疾步稳」，与之最不应并列的是：', '["A. 循序渐进", "B. 稳扎稳打", "C. 一哄而上", "D. 行稳致远"]', 'C', '一哄而上强调盲目冒进，与蹄疾步稳的稳健导向相悖。', '关注动宾搭配与政策语境。'),
(7, 14, '单选', '申论综合分析题中，「评价型」题目的标准结构是：', '["A. 表态→理由分析→对策或总结", "B. 标题→主送机关→落款", "C. 抄录材料→摘抄→复述", "D. 只写对策不分析"]', 'A', '评价型综合分析按表态、正反分析、对策或总结展开。', '评价型常含「辩证看待」。'),
(7, 14, '单选', '贯彻执行题撰写「倡议书」时，一般不需要的部分是：', '["A. 标题与称谓", "B. 背景目的与倡议分条", "C. 号召性结尾", "D. 刑法全文附录"]', 'D', '倡议书重格式完整与倡议内容，无需附录法律全文。', '格式分：标题、称谓、正文、落款。'),
(7, 22, '单选', '使用申论热点素材时，最忌讳的是：', '["A. 理解金句含义后调用", "B. 案例记「主体+做法+成效」", "C. 大段堆砌与题干无关热点", "D. 根据题干裁剪对策条目"]', 'C', '素材须扣题融合，堆砌无关热点会偏离材料主旨。', '素材是锦上添花，扣题才是根本。'),
(7, 22, '单选', '申论素材库中，「发展与安全」类热点通常可用于论证：', '["A. 只写个人兴趣爱好", "B. 统筹高质量发展与高水平安全", "C. 完全脱离国情空谈", "D. 只抄数据不分析"]', 'B', '发展与安全是国考高频主题，适用于对策与大作文论证。', '每个热点记 1 条金句 + 1 个案例。'),
(7, 22, '多选', '申论素材「三要素记忆法」包括：（多选）', '["A. 核心金句", "B. 典型案例", "C. 对策表述", "D. 随机网络段子"]', 'ABC', '指南建议记金句、案例、对策三要素，并能用自己的话复述。', '先理解再背诵，避免写错中央表述。'),
(3, 8, '单选', '数量公式：甲、乙两地相距 360 km，甲速 100 km/h，乙速 80 km/h，相向而行。甲先独自行驶 80 km 后乙才出发，问相遇时乙距 A 地约多少千米？', '["A. 140", "B. 155.6", "C. 160", "D. 180"]', 'B', '甲先走 80 km 后，剩余 280 km 相向而行，t=280÷180=14/9 h，乙行驶 80×14/9≈124.4 km？手册按甲速 100 计：100×14/9≈155.6 km 为相遇点距 A 地距离。', '行程问题先画线段图，注意先后出发。'),
(3, 8, '单选', '工程问题：甲单独 10 天完成，乙单独 15 天完成，两人合作需要多少天？', '["A. 5 天", "B. 6 天", "C. 7 天", "D. 8 天"]', 'B', '合作效率 1/10+1/15=1/6，需 6 天。', '设工作总量为时间公倍数。'),
(3, 8, '单选', '浓度问题：20% 盐水 300 克，要配制 15% 盐水需加水多少克？', '["A. 50 克", "B. 80 克", "C. 100 克", "D. 120 克"]', 'C', '溶质 60 克不变，60÷0.15=400 克溶液，加水 100 克。', '十字交叉或溶质守恒。'),
(7, 13, '单选', '申论归纳概括题的首要要求是：', '["A. 辞藻华丽、篇幅越长越好", "B. 全面准确、简洁规范", "C. 完全照搬材料原文", "D. 脱离材料自由发挥"]', 'B', '归纳概括需全面准确、适度提炼，忌照抄与漏点。', '先找标志词，再分类整合。'),
(7, 13, '单选', '综合分析题「解释型」的标准结构是：', '["A. 释义→分析→总结", "B. 对策→举例→号召", "C. 标题→落款→日期", "D. 抄录→摘抄→复述"]', 'A', '解释型综合分析按释义、分析、总结（或升华）展开。', '综合分析不可只列对策，须先解释题干。'),
(7, 13, '单选', '贯彻执行题（倡议书）一般不需要的要素是：', '["A. 标题", "B. 称谓", "C. 落款日期", "D. 刑法条文全文"]', 'D', '倡议书含标题、称谓、正文、落款日期；无需引用刑法全文。', '应用文先保格式分，再保内容分。'),
(7, 13, '单选', '提出对策类申论题，对策应主要来源于：', '["A. 材料中的问题与原因", "B. 个人随意编造", "C. 网络段子", "D. 与材料无关的热点堆砌"]', 'A', '对策须针对材料问题，可行、具体，一一对应。', '每条对策写清主体+手段+目的。'),
(7, 14, '单选', '申论提出对策题中，下列表述最规范的是：', '["A. 加强领导，高度重视", "B. 政府补启动、企业管运营、社会来监督", "C. 多多宣传", "D. 想办法解决"]', 'B', '规范对策须主体、手段、目的明确，避免空泛套话。', '避免「加强领导」类空话。'),
(7, 14, '单选', '申论大作文立意应：', '["A. 脱离材料自由发挥", "B. 紧扣材料与题干", "C. 只抄材料不讲观点", "D. 篇幅越短越好"]', 'B', '大作文立意须源于材料，观点明确、论证充分。', '由材料案例升华到政策层面。'),
(7, 18, '单选', '2026 年国考申论考试时限为：', '["A. 120 分钟", "B. 150 分钟", "C. 180 分钟", "D. 210 分钟"]', 'C', '申论考试时限 180 分钟（3 小时）。', '考前熟记各模块时限。'),
(7, 18, '单选', '申论「先立后破」的含义最准确的是：', '["A. 先关停所有传统产业", "B. 先培育新动能再稳妥调整旧动能", "C. 只发展新兴产业", "D. 照搬单一发展模式"]', 'B', '先立后破强调在培育新动能同时稳妥推进转型，避免简单关停。', '政策表述题抓官方定义。'),
(7, 22, '单选', '申论素材使用的正确做法是：', '["A. 大段堆砌与题干无关热点", "B. 准确调用、扣题融合", "C. 只背金句不理解含义", "D. 完全不用任何案例"]', 'B', '素材价值在于准确调用并与材料主旨融合，忌堆砌。', '记「地点/主体+做法+成效」三要素。'),
(1, 23, '单选', '国考职位表中，「职位类别」主要决定：', '["A. 申论试卷类别", "B. 面试着装颜色", "C. 体检医院", "D. 准考证字号"]', 'A', '职位类别决定申论试卷类型，备考须对应。', '选岗时核对专业、学历、政治面貌。'),
(1, 23, '单选', '报名国考时，「专业」字段应：', '["A. 随意填写相近专业", "B. 与毕业证书专业名称严格对应", "C. 写想学的专业", "D. 留空"]', 'B', '资格审查以毕业证书专业为准，须严格对应。', '对照教育部专业目录核对。'),
(4, 10, '单选', '图形推理：元素组成相同，应优先考虑：', '["A. 数量类", "B. 位置类", "C. 样式类求异", "D. 属性类对称"]', 'B', '元素组成完全相同，优先平移、旋转、翻转等位置规律。', '图形题：相同→位置，相似→样式，不同→数量。'),
(4, 10, '单选', '图形推理：元素组成不同且杂乱，应优先考虑：', '["A. 位置平移", "B. 黑白运算", "C. 数量类（点线角面素）", "D. 翻转"]', 'C', '元素组成不同，常考点、线、角、面、素等数量规律。', '先数后形，先整体后局部。'),
(6, 12, '多选', '下列属于可再生能源的有：（多选）', '["A. 太阳能", "B. 风能", "C. 煤炭", "D. 水能"]', 'ABD', '太阳能、风能、水能（含水电）为可再生能源；煤炭为化石能源。', '多选题用排除法，先剔除明显错误项。'),
(6, 12, '多选', '根据宪法，下列属于公民基本权利的有：（多选）', '["A. 受教育权", "B. 言论自由", "C. 依法纳税", "D. 人身自由"]', 'ABD', '受教育权、言论自由、人身自由属于基本权利；依法纳税是义务。', '区分「权利」与「义务」是常识多选常考点。'),
(6, 12, '多选', '2025—2026 年时政热点中，与「新质生产力」相关的表述有：（多选）', '["A. 以科技创新为主导", "B. 摆脱传统经济增长方式", "C. 主要依靠要素投入扩张", "D. 具有高科技、高效能、高质量特征"]', 'ABD', '新质生产力强调创新驱动与高质量发展，而非要素粗放投入。', '政策类多选抓文件原文关键词。'),
(2, 7, '多选', '下列各句中，没有语病且有语病排查价值的有：（多选）', '["A. 通过这次学习，使我提高了认识", "B. 他勤奋学习，成绩一直名列前茅", "C. 能否坚持锻炼，是身体健康的关键", "D. 我们要认真克服并发现工作中的缺点"]', 'ACD', 'A 缺主语，C 两面一面，D 语序不当；B 无语病。', '语病多选优先看主语、搭配、两面词。'),
(2, 6, '多选', '下列成语使用恰当的有：（多选）', '["A. 改革要蹄疾步稳", "B. 他对批评不以为然", "C. 这项政策差强人意，令人失望", "D. 各地应因地制宜发展产业"]', 'ABD', '差强人意指大体上还能让人满意，与「令人失望」矛盾，C 使用不当。', '成语题注意褒贬色彩与易混词。'),
(5, 11, '多选', '资料分析中，适合用「截位直除」的情形有：（多选）', '["A. 选项首位数字不同", "B. 计算基期量", "C. 比较分数大小且选项差距明显", "D. 精确到小数点后四位"]', 'ABC', '截位直除用于估算与比较；要求极高精度时不适用。', '速算技巧题结合选项差距判断方法。'),
(5, 11, '多选', '已知某地区 2024 年进出口总额增长 8%，出口增长 12%，进口增长 3%。下列说法正确的有：（多选）', '["A. 出口增速快于整体增速", "B. 进口增速慢于整体增速", "C. 出口对总额增长的贡献可能更大", "D. 进出口总额一定下降"]', 'ABC', '出口、进口增速一快一慢，整体增速介于其间；D 与题干矛盾。', '混合增长率题用整体介于部分之间判断。'),
(1, 5, '多选', '关于「中国式现代化」，下列理解正确的有：（多选）', '["A. 是人口规模巨大的现代化", "B. 是全体人民共同富裕的现代化", "C. 是走和平发展道路的现代化", "D. 可以照搬西方现代化模式"]', 'ABC', '中国式现代化有五个中国特色，不能照搬西方模式。', '政治理论多选以二十大报告表述为准。'),
(4, 10, '多选', '图形推理中，常见考查维度有：（多选）', '["A. 对称性", "B. 封闭区域数", "C. 笔画数", "D. 元素种类与位置"]', 'ABCD', '图形推理常从对称、数量、样式、位置等多维度命题。', '图形题先数后形，先整体后局部。'),
(4, 21, '多选', '加强型论证题中，下列能支持论点「运动有助于改善睡眠」的有：（多选）', '["A. 运动人群平均入睡时间缩短", "B. 运动能提高体内褪黑素水平", "C. 失眠患者普遍不爱运动", "D. 运动后体温下降有助于入睡"]', 'ABD', 'C 说明相关但未建立运动改善睡眠的因果；A、B、D 提供机制或效果支持。', '加强削弱题区分「因果支持」与「相关描述」。'),
(7, 14, '多选', '申论作答中，符合「归纳概括」规范的做法有：（多选）', '["A. 分条列点、层次清晰", "B. 照搬材料原文不加工", "C. 使用规范书面语", "D. 完全脱离材料主观发挥"]', 'AC', '归纳概括要全面准确、适度提炼；忌照搬冗长与脱离材料。', '申论小题先找标志词再分类整合。'),
(3, 9, '多选', '下列属于经典「工程问题」解题思路的有：（多选）', '["A. 设工作总量为时间公倍数", "B. 赋值效率求解合作时间", "C. 只凭直觉估算不做列式", "D. 用 1/效率 求单独完成时间"]', 'ABD', '工程问题常用赋值法与效率相加；纯直觉估算不可靠。', '数量关系多选关注方法而非单题答案。');
